-- curated_content.sql — UPDATE curated_description + curation_details, keyed (family, root_cause_id)
BEGIN;
UPDATE wiki_pages SET curated_description = '{"title": "Downstream API Latency Exceeds Integration Gateway Timeout Causing 504 Errors", "symptoms": "Affected users experience intermittent or sustained failures of scheduled data synchronization jobs routed through the Integration Gateway to downstream API endpoints — including internal services, billing APIs, CRM endpoints, and third-party vendor APIs. The primary symptom is repeated HTTP 504 Gateway Timeout responses when downstream API response times spike well beyond the gateway''s configured timeout threshold (typically 15–30 seconds, though in some cases as low as 2–5 seconds). Failures cluster during overnight or early-morning batch processing windows, often spanning 20 minutes to over two hours, and affect multiple gateway nodes and pods across Kubernetes clusters rather than isolated instances.\n\nGateway monitoring dashboards and distributed traces consistently show downstream p95/p99 response latency climbing dramatically — from baselines of approximately 200 milliseconds to 1–3 seconds up to peaks of 7–72 seconds — directly causing the gateway to terminate requests before responses are received. The resulting 504 errors cascade into retry exhaustion, message queue backlogs (in some cases exceeding 4,200 pending messages), and delayed or blocked data availability for dependent workflows such as finance reporting, analytics pipelines, and billing integrations. In some incidents, over 340 consecutive timeout errors were logged within a 90-minute span.\n\nAuthentication failures, rate-limiting responses, and credential expiry are consistently ruled out during investigation; gateway logs show no HTTP 401/403 or 429 responses, and token validation confirms valid credentials. Where token rotation was performed as an early troubleshooting step, it did not resolve the core 504 timeout pattern. Gateway-side actions such as pod restarts and cache clears similarly fail to eliminate the issue. Resolution occurs only after downstream API teams address service-side performance conditions such as resource exhaustion, misconfigured connection pools, or missing database indexes.", "cause": "Elevated latency on downstream API services caused Integration Gateway outbound requests to exceed the configured timeout window, producing intermittent or sustained HTTP 504 Gateway Timeout responses. The downstream performance degradation was traced to backend conditions such as resource exhaustion, misconfigured connection pools, or missing database indexes. Token expiry and rate-limiting were investigated but not supported by available evidence as contributing factors.", "variations": "- In one instance, a recent gateway deployment introduced intermittent HTTP 401 Unauthorized responses alongside the dominant 504 pattern; approximately 15% of requests returned authorization errors resolved by token rotation, but 504 timeouts persisted independently.\n- Gateway timeout configurations varied across incidents, ranging from as low as 2–5 seconds to the more common 30-second threshold, causing failures at correspondingly different downstream latency levels.\n- Some incidents involved external third-party partner APIs with no prior maintenance notice, while others involved internal downstream services; the timeout behavior was identical in both cases.\n- Incomplete telemetry was reported in at least one incident, where request correlation IDs were not propagated from the gateway to the monitoring system, requiring manual timestamp-based correlation.\n- Queue backlog severity varied significantly; one instance recorded over 4,200 pending messages while others reported sync lag exceeding 45 minutes without specific queue depth metrics.\n- One downstream root cause was traced to a misconfigured connection pool on the API ingest tier; another was traced to a full table scan caused by a missing database index after a schema migration.\n- In one case, the morning data availability report — rather than real-time alerting — was the first indicator of failure, as sync jobs had run overnight unattended.\n- Rate limiting (HTTP 429) was considered in some occurrences but ruled out during investigation; no throttling responses were observed in gateway logs.", "reporting": "Resolved by IT; downstream API latency exceeded the Integration Gateway timeout threshold, causing 504 Gateway Timeout errors and batch sync job failures during scheduled processing windows."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:34:28.587254+00:00", "final_grade": "Accepted"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/downstream-api-latency-exceeds-timeout';
UPDATE wiki_pages SET curated_description = '{"title": "Downstream API Rate-Limit Throttling Causes Gateway Timeout Integration Failures", "symptoms": "Affected users experience failures of scheduled and real-time integration jobs that route through the Integration Gateway when downstream external API endpoints enforce rate limits. The issue typically manifests as repeated HTTP 504 Gateway Timeout errors observed in application and gateway logs. Monitoring dashboards show sharply rising downstream latency, with p99 response times exceeding normal thresholds, and elevated error rates from external API endpoints. Integration jobs that previously completed successfully begin failing within minutes of onset, blocking normal data synchronization workflows.\n\nThe underlying mechanism involves the external API returning HTTP 429 (Too Many Requests) responses due to quota enforcement, particularly during periods of high request volume such as nightly batch ingestion or overnight sync windows. The Integration Gateway''s retry logic causes pending requests to queue rapidly — climbing from a handful to over a hundred within minutes — until each request exceeds the gateway''s timeout threshold. This retry-stacking behavior converts the downstream throttling condition into widespread gateway timeouts visible to end users and dependent applications.\n\nThe issue affects integration paths used by reporting applications and customer data synchronization services alike, creating backlogs in gateway worker queues and delaying or entirely preventing data record updates. Affected teams observe that the downstream endpoint remains reachable and responds normally to individual test calls, confirming the external service is not fully unavailable — rather, the volume of concurrent or retried requests triggers rate-limit enforcement that cascades into job failures across the integration platform.", "cause": "The downstream API enforced rate limits against the integration client, producing sustained HTTP 429 Too Many Requests responses. Gateway retries accumulated under elevated latency, exhausted the effective timeout window, and resulted in HTTP 504 Gateway Timeout errors that caused integration job failures and delayed data syncs.", "variations": "- Initial error logs may include HTTP 401 Unauthorized responses alongside the 504 timeouts, leading to an initial suspicion of authentication or credential rotation issues before downstream throttling is confirmed as the root cause.\n- Both real-time data sync jobs and scheduled batch ingestion jobs may be affected simultaneously when they share the same integration gateway path and downstream API quota.\n- The gateway worker queue backlog may persist and continue growing even after the initial throttling event, as retries from earlier failed jobs compound with new incoming requests.", "reporting": "Resolved by IT after identifying that downstream API rate-limit enforcement triggered retry exhaustion and gateway timeouts across integration jobs."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:35:06.168832+00:00", "final_grade": "Accepted"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/downstream-rate-limiting-throttling';
UPDATE wiki_pages SET curated_description = '{"title": "Expired Integration Gateway API Token Causes Sync Timeouts", "symptoms": "Affected users experience failures of scheduled data synchronization jobs when the Integration Gateway attempts authenticated API calls using an expired service account token. The issue typically surfaces during overnight or early-morning sync windows, when outbound calls begin returning HTTP 401 Unauthorized responses with token-expired indicators. The gateway''s retry logic repeatedly attempts to re-authenticate with the same invalid credential, accumulating retries with exponential backoff until timeout thresholds are reached, at which point calls fail with HTTP 504 Gateway Timeout errors. In some cases, retry storms also trigger HTTP 429 Too Many Requests rate-limiting responses from downstream endpoints.\n\nThe downstream impact is significant: scheduled sync workflows—including customer record synchronization, order fulfillment, finance reconciliation, HR data pipelines, and partner data delivery—stall or fail entirely. Pending job backlogs range from approximately 1,400 to over 14,000 records depending on sync volume. Data availability for dependent consumers such as morning dashboards, CRM pipelines, and compliance feeds is delayed by several hours. Affected users typically discover the problem through monitoring alerts during the batch window or during morning reviews when dashboards display stale or missing data.\n\nInvestigation consistently reveals that the bearer token or API credential assigned to the gateway service account has exceeded its mandatory rotation window. In some instances, an automated token rotation job fails silently before the sync window; in others, credentials simply age past the configured expiry policy without any rotation attempt. Gateway logs show failed token refresh attempts and cascading authentication errors, while API call latency increases dramatically from normal baselines to multiple seconds as retries consume gateway processing capacity.", "cause": "An expired API token on the Integration Gateway prevented authenticated calls to downstream API endpoints. The token had lapsed either because the automated credential rotation job failed or because the credential was not rotated within the required policy window, leaving the gateway using invalid credentials for all outbound authenticated requests.", "variations": "- In some cases, the automated token rotation job failed silently without generating an alert, allowing the credential to expire undetected before the sync window.\n- The issue has been observed across multiple regions and infrastructure configurations, including standalone gateway hosts and Kubernetes-based pod deployments.\n- In certain instances, only 504 Gateway Timeout responses were visible initially, with 401 Unauthorized errors surfacing only in deeper log analysis.\n- HTTP 429 Too Many Requests responses accompanied some incidents due to retry storms, while other instances showed only 504 and 401 errors without rate-limiting behavior.\n- The issue affected multiple environments simultaneously (staging and production) when a shared service account token was used across both.\n- In some cases, the gateway configuration referenced an outdated token rotation policy version, compounding the missed rotation window.\n- Downstream endpoints varied across incidents—including CRM synchronization, order fulfillment, partner APIs, and internal service endpoints—but the error pattern remained consistent.\n- In one case, restarting the gateway pod and clearing its token cache did not resolve the issue, confirming the failure was credential-level rather than transient process state.", "reporting": "Resolved by IT through rotation of the expired API token, redeployment of the updated credential to the Integration Gateway, and restart of affected services to restore authenticated sync processing."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:38:26.769260+00:00", "final_grade": "Accepted"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/expired-api-token-auth-failures';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Retry Policy Amplifies Downstream Latency Into Gateway Timeout Storms", "symptoms": "Affected users experience failures during scheduled batch data synchronization jobs that route through the Integration Gateway to downstream API services. The issue manifests as repeated HTTP 504 Gateway Timeout responses when downstream service latency becomes elevated — in reported incidents, p99 latency spiked from approximately 1.2 seconds to 38 seconds, far exceeding the gateway''s configured timeout window. Sync jobs fail or are significantly delayed, with failure windows lasting approximately 30 minutes or longer and delaying data availability for downstream consumers in affected fulfillment groups and queues.\n\nThe core behavior observed is that the Integration Gateway''s deprecated retry and backoff policy amplifies the impact of downstream latency rather than mitigating it. When downstream services slow down, the gateway''s insufficiently bounded retries compound the load, producing retry storms visible in distributed tracing. This feedback loop causes the timeout condition to persist or worsen across the batch processing window, preventing sync jobs from completing successfully.\n\nGateway pod restarts alone do not resolve the issue. Temporarily increasing the gateway timeout threshold (for example, from 30 seconds to 60 seconds) reduces immediate failure counts for some traffic but does not address the underlying retry amplification. The issue is not related to authentication failures, token expiry, or rate-limiting errors; logs confirm that only timeout-class errors are present during the affected windows.", "cause": "Elevated downstream service latency caused upstream request timeouts through the Integration Gateway. The impact was amplified because the gateway was still configured with a stale, deprecated retry and backoff policy that extended retry behavior beyond the effective integration window, producing retry storms that compounded load on the already-slow downstream service. Available evidence points to downstream response slowness with possible transient throttling pressure rather than an authentication failure.", "variations": "- Nightly batch sync jobs fail entirely within the affected window, delaying data availability for downstream inventory consumers.\n- Intermittent 504 responses affect order fulfillment sync pipelines, causing delayed but not always fully failed jobs.\n- Retry storms are visible in distributed tracing, indicating compounding load on the downstream service during the timeout window.\n- A gateway pod restart does not resolve the issue, and no recent deployment change to timeout settings is identified.\n- Temporarily extending the gateway timeout threshold reduces immediate failure counts but does not eliminate the retry amplification behavior.", "reporting": "Resolved by IT; reference Integration Gateway deprecated retry policy causing 504 timeout storms during batch sync processing."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:39:05.298631+00:00", "final_grade": "Accepted"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/stale-retry-backoff-amplifies-latency';
UPDATE wiki_pages SET curated_description = '{"title": "Integration Gateway Timeout and Sync Failures During Scheduled Batch Windows", "symptoms": "Affected users experience failures in scheduled integration jobs that transmit data through the Integration Gateway to downstream API endpoints. Jobs return HTTP 504 Gateway Timeout responses, and in some incidents HTTP 429 rate-limit responses are also observed. Retry attempts fail to clear the resulting backlog, with queue depth climbing rapidly — in observed cases reaching approximately 4,200 pending order records or 14,000 unsynced customer records. The user-visible impact is missing or delayed data in downstream applications, typically noticed during daily reconciliation or when operations dashboards reflect growing backlogs of unprocessed records.\n\nThe interaction between authentication state and throttling behavior varies across incidents. In one confirmed case, the Integration Gateway was authenticating outbound API calls with an expired cached token — last rotated over 95 days prior against a 90-day TTL — and the downstream API simultaneously returned 429 throttling once retry storms developed. In another incident, credential failure could not be confirmed; the service account token passed post-incident validation, though runtime authentication state during the failure window remained uncertain. In that case, downstream endpoint latency spiked sharply (median response time climbing from approximately 220 ms to over 4,800 ms) with only isolated 429 responses observed.\n\nAcross all observed incidents, the failures are confined to the Integration Gateway processing path and do not affect direct application submissions. Impact begins during scheduled sync windows — typically overnight or early-morning UTC — and persists until token validity, retry behavior, and gateway timeout configurations are corrected or adjusted.", "cause": "A stale expired API token cached on the Integration Gateway caused failed or delayed authenticated requests, while concurrent downstream API rate limiting (HTTP 429) amplified retries and pushed requests past the gateway timeout window. However, the primary cause remains unconfirmed in some incidents because Integration Gateway logs for the failure window and token rotation history were not always available. Available evidence supports an upstream integration timeout condition affecting outbound calls, with the most likely contributors being expired integration credentials, downstream API latency beyond the configured timeout window, or API rate limiting during overnight batch processing.", "variations": "- In some incidents, both an expired cached API token and HTTP 429 rate-limit responses from the downstream service are confirmed as contributing factors; in others, credential failure is not confirmed and the root cause remains mixed or inconclusive.\n- Some incidents show prominent HTTP 429 rate-limit responses alongside 504 timeouts, while others exhibit primarily 504 and ETIMEDOUT failures with only isolated or absent 429 indicators.\n- Downstream endpoint latency may spike significantly (e.g., p99 exceeding 6 seconds against a 30-second timeout threshold) even when explicit throttling or authentication rejection is not observed.\n- Trace sampling limitations (e.g., 10% sampling rate) may restrict diagnostic coverage of the exact failed requests, leaving the root cause partially unconfirmed.\n- In at least one incident, manual retry handling was initiated by operations staff to limit impact while the sync workflow remained blocked.", "reporting": "Resolved by IT; reference Integration Gateway batch sync failures with HTTP 504/429 responses and backlog accumulation during scheduled overnight processing windows."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:40:58.732557+00:00", "final_grade": "Accepted"}' WHERE family = 'AIT' AND root_cause_id = 'AIT/unconfirmed-mixed-credential-latency-throttling';
UPDATE wiki_pages SET curated_description = '{"title": "Incomplete Password Reset Due to Expired Reset Token", "symptoms": "Affected users experience persistent sign-in failures across the SSO portal and Microsoft 365 applications after completing a corporate password reset through the Password Reset Portal. Despite the reset appearing to finish successfully, the new password is not accepted consistently, and the affected user''s Active Directory account becomes locked again shortly afterward.\n\nThe issue manifests across multiple devices, such as desktops and mobile devices, rather than being isolated to a single endpoint. Although initial investigation may consider stale cached credentials on mobile devices or other endpoints as a potential locking source, diagnostics rule these out as the cause of the continued lockouts.\n\nThe confirmed root cause is an invalid or incomplete prior reset state. Reissuing a valid reset token resolves the issue, restoring normal password propagation and sign-in behavior across all affected services and devices.", "cause": "The previous password reset did not complete successfully because the reset token had expired or was no longer valid. This left the affected user attempting authentication with credentials that were not fully updated in directory services.", "variations": "- The affected user''s Active Directory account is observed as locked on a specific domain controller shortly after the reset attempt.\n- The affected user has saved or cached credentials on a mobile device, but these are ruled out as the source of the continued lockouts.", "reporting": "Resolved by IT after reissuing a valid password reset token to complete credential propagation across directory services."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:41:58.123170+00:00", "final_grade": "Accepted"}' WHERE family = 'ALP' AND root_cause_id = 'ALP/expired-reset-token-primary';
UPDATE wiki_pages SET curated_description = '{"title": "Recurring AD Lockouts from Unidentified Stale Credential Source Post-Reset", "symptoms": "Affected users experience repeated Active Directory account lockouts shortly after completing a corporate password reset through the Password Reset Portal. Despite the password change propagating successfully to domain controllers, the account continues to lock at regular intervals — typically every few minutes to every fifteen minutes. Users encounter \"account locked\" or \"invalid password\" errors and are unable to access corporate applications including the SSO Portal, Outlook, and OWA mailbox services.\n\nThe lockouts persist even when the user''s desktop authentication is functioning normally. The recurring lock events are attributed to stale credentials cached on a device or service that continues to authenticate with the old password in the background. However, the exact source of the failed authentication attempts cannot be definitively identified from available logs; the caller computer name field in lockout event entries is sometimes blank or points to a non-interactive caller rather than a clearly identifiable endpoint.\n\nMobile devices with cached credentials are a common suspected source, but in some cases lockouts continue after the user has removed and re-added corporate accounts on the device, indicating an unidentified background service or legacy application as the true cause.", "cause": "A non-mobile service, legacy client, or integrated application continued using outdated stored credentials after the user''s password reset, repeatedly triggering Active Directory lockouts. Insufficient authentication telemetry — such as blank or ambiguous caller computer name fields in lockout logs — prevented definitive identification of the offending source.", "variations": "- Lockout events correlate with a known mobile device IP address and cease to recur after account unlock and fresh token issuance, with the mobile device remaining the most likely — but unconfirmed — source.\n- Lockouts persist at the same interval even after the user removes and re-adds the corporate account on the suspected mobile device, indicating a separate background service or integrated application authenticating with stale credentials.\n- The caller computer name field in Event ID 4740 lockout logs appears intermittently blank, preventing definitive identification of the offending endpoint.\n- Lockout source logged on the domain controller points to a non-interactive caller ID rather than an ActiveSync or mobile user-agent, requiring escalation to the identity or messaging team for service-side remediation.", "reporting": "Resolved by IT through account unlock and coordination with identity or messaging teams to isolate and remediate the stale credential source; reference \"recurring AD lockout – unidentified stale credential source post-reset.\""}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:43:03.896958+00:00", "final_grade": "Accepted"}' WHERE family = 'ALP' AND root_cause_id = 'ALP/stale-credentials-unidentified-source';
UPDATE wiki_pages SET curated_description = '{"title": "Recurring AD Lockouts From Stale Cached Credentials on iOS Mobile Devices", "symptoms": "After completing a password reset through the corporate Password Reset Portal, affected users experience repeated Active Directory account lockouts. The new password functions correctly for desktop sign-in, but mobile devices — typically company iPhones running apps such as Outlook, Teams, Mail, and Safari — continue submitting the old cached credentials in the background. These stale authentication attempts rapidly exceed the AD lockout threshold, triggering Event ID 4740 lockout entries on the domain controller and re-locking the account within minutes of each unlock.\n\nThe issue creates a persistent lockout cycle: each time the account is unlocked, the mobile device resumes retrying with outdated credentials, exhausting the failed-attempt counter again. Domain controller logs confirm the repeated failures originate from the mobile device''s IP address, with automated retries occurring as frequently as every 60 seconds. In some cases, 14 or more failed attempts were recorded within a 25-minute window from a single device. Users remain locked out of all SSO-protected corporate resources — including Exchange Online, Teams, and internal tools — until the stale credentials on the mobile device are cleared.\n\nA secondary symptom compounds the problem: the lockout may block access to the Password Reset Portal itself, preventing self-service recovery. In some cases the reset token has also expired, leaving affected users unable to resolve the issue without direct service desk intervention. The lockout cycle has persisted for extended periods — in one case spanning over eleven hours across multiple unlock attempts — affecting users across multiple departments, office locations, and network environments.", "cause": "Cached credentials on the affected user''s iOS mobile device continued submitting the old password to Active Directory and SSO-connected services after the password reset. The repeated failed authentication attempts triggered the AD lockout policy before the new password could be used successfully, creating a recurring lockout cycle until the stale credentials were removed from the device.", "variations": "- Desktop sign-in succeeds normally after the password reset while only the mobile device triggers lockouts, giving the impression the reset was partially successful.\n- The lockout prevents access to both the SSO Portal and the Password Reset Portal simultaneously, leaving the user unable to self-remediate.\n- Multiple lockout-and-unlock cycles occur over an extended period (e.g., overnight) when the mobile device continues retrying cached credentials at regular sync intervals.\n- Saved passwords in the mobile browser (e.g., Safari) contribute to the lockout in addition to credentials stored in mail and collaboration apps.\n- A previously issued password reset token became expired or unusable due to the repeated lockouts, requiring a fresh token to be generated.\n- Some affected users were traveling or connecting from remote or home networks, indicating the issue is not tied to a specific network location.\n- Some tickets required escalation to Identity Tier 2 to validate reset propagation across directory services and clear the mobile credential source.\n- In at least one case the affected device was running an older mobile OS version, which may have contributed to credential caching behavior.", "reporting": "Resolved by IT after unlocking the Active Directory account and clearing stale cached credentials from the affected mobile device."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:46:28.460041+00:00", "final_grade": "Accepted"}' WHERE family = 'ALP' AND root_cause_id = 'ALP/stale-mobile-cached-credentials';
UPDATE wiki_pages SET curated_description = '{"title": "Mobile Cached Credentials Trigger AD Lockout With Expired Reset Token", "symptoms": "Affected users experience Active Directory account lockouts triggered by mobile devices—primarily corporate iPhones, though managed Android devices are also represented—that continue submitting stale cached credentials after a password change or reset. Mail and collaboration apps such as Outlook, Teams, native iOS Mail, and Microsoft Authenticator retry authentication in the background using outdated saved passwords, rapidly exceeding the lockout threshold. Domain controller security logs (Event ID 4740/4625) show clusters of failed attempts originating from the mobile device''s IP address, in some cases over fourteen failures within a short window.\n\nCompounding the lockout, the self-service password reset token issued by the Password Reset Portal expires before the user can complete the credential update. Token validity windows vary across environments, with observed time-to-live values ranging from fifteen minutes to several hours; in one case the token sat unused for over twenty-four hours. Users who return to the reset link encounter an expired-token error, leaving them without a viable self-service recovery path while the account remains locked and the mobile device continues generating failed attempts.\n\nEven when the Password Reset Portal reports a successful reset, the account may relock almost immediately because the mobile device keeps submitting old credentials before the new password propagates across domain controllers. This self-reinforcing cycle of stale-credential submission, account lockout, and unusable reset token blocks access to all SSO-connected resources—including email, collaboration tools, CRM, and identity platforms—from both mobile and desktop clients. Affected users consistently report urgent business impact, citing time-sensitive deliverables or client commitments. Resolution requires administrative intervention to unlock the account, issue a fresh reset token, and confirm that cached credentials on the mobile device are cleared.", "cause": "The Active Directory lockout policy was triggered by repeated failed authentication attempts from a mobile device that continued submitting stale cached credentials after a password change or reset. Simultaneously, the self-service password reset token expired before the credential update could be completed and propagated, preventing the user from resolving the lockout through self-service recovery.", "variations": "- Desktop authentication succeeds with the new password while mobile authentication fails, with the lockout triggered exclusively by the mobile device\n- Multiple mobile apps on the same device (e.g., Outlook, native iOS Mail, Teams, Microsoft Authenticator) each independently retry with stale credentials, accelerating the lockout\n- The lockout recurs immediately after an initial account unlock because cached mobile credentials have not yet been cleared on the device\n- A previous device continues submitting stale credentials after the user migrates to a new phone, with old device profiles or backup-restored credentials driving the failures\n- Domain controller replication lag contributes to post-reset SSO failures, with updated credentials not propagating consistently across all domain controllers\n- In at least one case the lockout preceded any password reset attempt; initial sign-in failures on the mobile device triggered the AD lockout policy before self-service recovery was initiated\n- Token time-to-live values varied across environments, with observed windows ranging from fifteen minutes to four or more hours\n- In one case the user removed and re-added the corporate account on the mobile device prior to contacting support, but the reset portal still reported the token as expired and SSO continued rejecting sign-in attempts", "reporting": "Resolved by IT after unlocking the Active Directory account, issuing a new password reset token, and clearing stale cached credentials from the mobile device."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:54:17.173808+00:00", "final_grade": "Accepted"}' WHERE family = 'ALP' AND root_cause_id = 'ALP/stale-mobile-credentials-plus-expired-reset-token';
UPDATE wiki_pages SET curated_description = '{"title": "Expired Certificate on Load Balancer After Automated Renewal Failure", "symptoms": "Affected users and dependent internal systems experience TLS handshake failures when attempting to connect to internal web services over HTTPS. Browsers display certificate date warnings (typically \"NET::ERR_CERT_DATE_INVALID\") when navigating to the service URL, and automated API calls, integration pipelines, health checks, and inventory sync processes that rely on the same endpoints begin failing TLS validation simultaneously. The affected internal web service is effectively unavailable over secure access for all clients hitting the endpoint.\n\nInvestigation reveals that the organization''s load balancer is presenting an expired certificate for the internal service. The certificate''s validity period has lapsed, and the full certificate chain — including the leaf certificate and any intermediate CA bundles — remains stale on the load balancer. OpenSSL client checks from diagnostic hosts confirm that the certificate common name and subject alternative name entries match the service, but the expiration date has passed. Multiple workstations and automated systems across affected offices reproduce the error.\n\nThe root cause traces back to the automated certificate renewal process failing to complete before the expiration date. In some cases the renewal job encountered an access-denied error due to permissions being revoked during a recent RBAC policy change; in others the renewal script returned a non-zero exit code on its last attempted invocation without triggering any notification. A contributing factor across all incidents is that certificate expiry monitoring or alerting had been disabled — often weeks or months prior to the expiration — as a result of a configuration change, so no pre-expiry warning was generated to prompt manual intervention.", "cause": "The TLS certificate for an internal service expired on the load balancer because the automated renewal process failed to complete. The renewal job was unable to update the load balancer configuration due to missing permissions (access denied) following an RBAC policy change, and certificate expiry monitoring had been disabled, so no pre-expiry alert was raised to prompt manual remediation.", "variations": "- The automated renewal job failed specifically because its service account lost required permissions following an RBAC policy update, resulting in an \"access denied\" error when pushing the renewed chain to the load balancer.\n- The renewal script executed but returned a non-zero exit code without generating an alert, and no subsequent retry was attempted before the certificate expired.\n- The certificate expiry alerting rule was found to have been explicitly disabled weeks or months before the expiration event, preventing any pre-expiry notification from being raised.\n- Load balancer health checks against backend pools reported TLS errors, compounding the outage by marking backends as unhealthy in addition to blocking direct user access.\n- Dependent automated workflows — such as inventory sync services, DevOps integration pipelines, and monitoring dashboards — failed alongside browser-based access due to strict TLS validation.", "reporting": "Resolved by IT after reauthorizing the renewal service account, deploying the renewed certificate chain to the load balancer, and re-enabling certificate expiry alerting."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T17:54:59.334519+00:00", "final_grade": "Accepted"}' WHERE family = 'CES' AND root_cause_id = 'CES/automated-renewal-process-failed-to-complete';
UPDATE wiki_pages SET curated_description = '{"title": "Renewed Certificate Chain Not Deployed to Load Balancer Before Expiry", "symptoms": "Affected users attempting to access internal web services over HTTPS encountered browser certificate warnings — most commonly NET::ERR_CERT_DATE_INVALID and ERR_CERT_DATE_INVALID — along with TLS handshake failures that rendered services unreachable. The issue was reported across multiple offices and internal networks simultaneously, affecting both interactive browser sessions and programmatic clients such as CI/CD pipelines, API consumers, health-check monitors, and service-to-service integrations. Dependent systems experienced cascading failures including 502/523/525 HTTP errors, broken automation workflows, and disrupted business-critical applications such as payroll and inventory management.\n\nInvestigation consistently revealed that the load balancer fronting the affected service continued to present an expired leaf certificate and an outdated or incomplete intermediate certificate chain, even though a renewed certificate had already been issued by the internal Certificate Authority. The renewed certificate and full chain were never successfully deployed to the load balancer''s TLS termination configuration. In some cases a prior deployment attempt had been reported as complete but no corresponding configuration change existed on the load balancer. Restarting or reloading the load balancer service alone did not resolve the issue, as the listener configuration still referenced the old certificate material.\n\nA contributing factor across these incidents was a gap in certificate expiration monitoring. Pre-expiry alerting rules had been inadvertently disabled, suppressed, or misconfigured — in some cases during a prior maintenance window — so no advance warning was generated before the certificate expired. This monitoring gap allowed the incomplete deployment to go undetected until users and automated probes began reporting TLS failures.", "cause": "The TLS certificate for the internal web service expired, and the renewed certificate along with its full chain from the internal Certificate Authority was not deployed to the load balancer''s TLS termination configuration. The load balancer continued serving the expired leaf certificate and stale intermediate chain to clients. Certificate expiration monitoring and renewal alerting were inactive, misconfigured, or suppressed, preventing advance warning and allowing the deployment gap to persist until service impact occurred.", "variations": "- In one instance, only the renewed leaf certificate was deployed to the load balancer while the intermediate CA bundle was omitted, resulting in an incomplete trust chain rather than a fully expired certificate.\n- In one case, the renewed certificate was inconsistently deployed across a multi-node load balancer cluster, causing intermittent TLS failures depending on which node handled the request.\n- In one incident, the initial certificate bundle import to the load balancer failed due to incorrect chain ordering; the intermediate CA certificate had to be reordered before the root certificate for the reload to succeed.\n- Some incidents involved the expired certificate appearing on both the load balancer and the direct backend application port, indicating the stale certificate was present at multiple layers.\n- One environment used a Kubernetes ingress controller with a TLS secret still referencing the expired certificate bundle, rather than a traditional load balancer binding.\n- The monitoring suppression mechanism varied: in some cases a prior maintenance window disabled the alerting rule, while in others a misconfigured threshold or manually added filter suppressed the alert.\n- Downstream impacts ranged from CI/CD pipeline failures and blocked sprint deployments to disrupted payroll integrations and internal API authentication failures.\n- Certain incidents were first detected by automated Nagios health checks or synthetic monitoring probes rather than by end-user reports.", "reporting": "Resolved by IT; expired TLS certificate and stale chain on load balancer replaced with renewed full certificate chain after deployment gap and monitoring alert failure were identified."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:01:49.684838+00:00", "final_grade": "Accepted"}' WHERE family = 'CES' AND root_cause_id = 'CES/renewed-chain-not-deployed-to-lb-with-monitoring-gap';
UPDATE wiki_pages SET curated_description = '{"title": "Suspected Transient Certificate-Serving Fault on Load Balancer Unconfirmed", "symptoms": "Affected users at a corporate office reported TLS certificate warnings and failed connections when accessing an internal web service through an F5 load balancer. Browsers displayed a certificate date-invalid error when navigating to the service URL, and dependent internal API calls through the API gateway began failing TLS handshake validation simultaneously. The issue was initially surfaced by a platform engineer via internal chat and was subsequently confirmed by multiple users at the same site.\n\nAn affected workstation was used to reproduce the browser-side certificate warning, and a second user at the same office independently confirmed identical symptoms. The application remained unavailable to some internal consumers following the certificate-related alerts.\n\nHowever, the available troubleshooting data did not consistently show an expired certificate or chain defect on the F5 partition serving the relevant virtual IP at the time of diagnostic review. The investigation was unable to conclusively determine whether the certificate-serving fault was transient in nature, isolated to a specific client path or load balancer partition, or had already cleared before validation could be completed. Despite this evidentiary gap, the reported symptoms were consistent with a certificate-serving problem, and a matching fix was applied, after which the reported service impact cleared.", "cause": "Insufficient evidence existed to confirm a certificate expiration outage. The incident may have involved a transient or path-specific load balancer certificate presentation issue, but diagnostic access gaps and incomplete monitoring history prevented confirmation of the root cause.", "variations": "", "reporting": "Resolved by IT after applying a certificate-related fix to the F5 load balancer, though the root cause remained unconfirmed due to insufficient evidence captured during the active incident window."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:03:01.363103+00:00", "final_grade": "Accepted"}' WHERE family = 'CES' AND root_cause_id = 'CES/unconfirmed-tls-presentation-issue-evidence-gap';
UPDATE wiki_pages SET curated_description = '{"title": "Expired or Incomplete TLS Certificate Chain Served by Load Balancer", "symptoms": "Affected users attempting to access internal web services over HTTPS encounter TLS certificate errors that prevent normal connectivity. Browsers display certificate date-invalid warnings (such as NET::ERR_CERT_DATE_INVALID), while automated clients, API integrations, and backend monitoring services fail during the TLS handshake. The errors originate from load balancers serving certificate chains that are expired or incomplete — either the leaf certificate has passed its validity date, the intermediate certificate in the served chain is expired or missing, or both conditions are present simultaneously. Reports typically surface from multiple users and teams across affected offices, with both interactive browser sessions and automated service accounts unable to establish trusted connections.\n\nThe issue manifests as a complete or near-complete loss of HTTPS access to the affected internal service endpoint. Load balancer logs confirm chain validation errors and certificate date-invalid conditions beginning at the time of the reported outage. In some cases, certificate-management alerting that should have flagged upcoming expirations did not fire, meaning the expiration went undetected until users and dependent systems began failing. The disruption affects all internal clients connecting through the impacted load balancer virtual server, spanning workstations and automated integration hosts alike.\n\nThe condition persists — blocking normal internal application access for affected user groups — until the certificate chain served by the load balancer is corrected and the updated profile is active. In at least one case, the impact extended to approximately 40 interactive users and 12 automated service accounts across a regional deployment.", "cause": "The internal web service outage was caused by an expired CA-issued leaf TLS certificate combined with an outdated or missing intermediate certificate in the chain served by the load balancer. Certificate monitoring and renewal alerting failed to trigger before expiration, and in some cases a renewed leaf certificate was not properly installed or the deployment bundle lacked the correct intermediate certificate, leaving the load balancer presenting an incomplete or invalid chain.", "variations": "- In one instance, the leaf certificate itself remained valid, but the load balancer continued to serve an expired intermediate certificate following a recent renewal effort, causing the service to remain intermittently inaccessible until the corrected certificate bundle was applied to the load balancer''s SSL profile.\n- Some cases involved the intermediate certificate being entirely absent from the served chain rather than expired, resulting in both date-validity and chain-trust failures reported by clients.\n- In certain environments, the initial chain update attempt on the load balancer failed because the correct intermediate certificate file was not available in the deployment bundle, prolonging the outage beyond the first remediation effort.\n- Certificate-management monitoring rules were found to be misconfigured in at least one case, with incorrect alerting thresholds that prevented proactive detection of the approaching certificate expiration.", "reporting": "Resolved by IT after updating the certificate chain and SSL profile on the affected load balancer; reference: expired or incomplete TLS chain on load balancer causing internal HTTPS service outage."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:04:17.508973+00:00", "final_grade": "Accepted"}' WHERE family = 'CES' AND root_cause_id = 'CES/valid-leaf-but-stale-or-missing-intermediate-served';
UPDATE wiki_pages SET curated_description = '{"title": "Wrong Certificate Bound to Load Balancer Causing Hostname Validation Failures", "symptoms": "Internal users and automated dependent services experienced TLS failures when connecting to internal web and API endpoints through an F5 load balancer. Browser-based users encountered certificate warnings and SSL protocol errors, while automated integrations such as a payroll sync service failed with hostname mismatch and trust validation errors. The failures affected all traffic routed through the load balancer virtual IP in the affected region, even though the certificate bound to the endpoint was valid and not expired.\n\nThe root cause was that a valid certificate belonging to a different internal service had been bound to the load balancer instead of the certificate matching the expected hostnames. Because the certificate''s common name did not match the requested endpoints, TLS handshake validation failed for all clients enforcing hostname verification. Some clients reported a generic expired-certificate error code rather than a hostname mismatch, depending on the TLS library and validation behavior of the connecting application.\n\nThe organization''s certificate monitoring platform did not flag the condition because its checks were limited to certificate expiry rather than hostname or binding correctness. Monitoring continued to report the previous certificate chain fingerprint on the affected endpoint without raising an alert, effectively masking the misconfiguration.", "cause": "The F5 load balancer was updated with a current certificate that did not match the internal web service endpoint name. Although the renewal process completed successfully, the wrong certificate asset was bound to the virtual server, causing hostname validation failures for connecting clients.", "variations": "- Monitoring continued to report the old certificate chain fingerprint on the affected endpoint without raising an alert, masking the misconfiguration.\n- No change record was logged for the load balancer certificate binding during the most recent renewal window, leaving the incorrect binding undetected by change-management processes.\n- Some clients reported a generic expired-certificate error code rather than a hostname mismatch, depending on the TLS library and validation behavior of the connecting application.", "reporting": "Resolved by IT; incorrect certificate binding on F5 load balancer caused TLS hostname validation failures for internal web and API endpoints."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:05:13.870889+00:00", "final_grade": "Accepted"}' WHERE family = 'CES' AND root_cause_id = 'CES/wrong-certificate-bound-to-endpoint';
UPDATE wiki_pages SET curated_description = '{"title": "BitLocker Encryption Not Active or Attested Causing Noncompliance Block", "symptoms": "Affected users on corporate-managed Windows 10 and Windows 11 devices experience blocks when accessing protected Microsoft 365 resources — including SharePoint Online, Outlook, Exchange Online, and Dynamics 365. Conditional Access evaluates the devices as noncompliant in Intune because a healthy BitLocker encryption attestation signal is not being reported. Company Portal or the Intune admin console shows the affected devices as noncompliant, and users cannot reach protected applications until encryption status is correctly reported.\n\nThe underlying condition varies but consistently involves BitLocker encryption not being in a fully enabled and attested state. In some cases, encryption stalled during initial device provisioning and required local user interaction to complete setup. In other cases, BitLocker protection was found to be suspended on the endpoint, causing the compliance evaluation to return an unhealthy encryption state even though the device was otherwise online and scoped to the correct policy. A third presentation involves devices where encryption began only after a policy sync, with no prior encryption signal present.\n\nThe issue has been observed following the rollout of new or updated compliance policies requiring BitLocker device encryption. Multiple users and devices may be affected simultaneously within the same office or policy scope. In at least one case, a stale device check-in compounded the problem by further delaying the reporting of encryption status to Intune.", "cause": "After an encryption compliance requirement was enforced, a subset of managed endpoints either had BitLocker encryption disabled, suspended, or incomplete — or did not successfully report encryption attestation back to Intune. This caused device compliance to remain noncompliant and Conditional Access to deny access to protected resources. Once BitLocker was fully active and a successful policy refresh reported the encryption telemetry, compliance was restored.", "variations": "- Encryption setup stalled during initial device provisioning and required local user interaction (e.g., completing BitLocker setup and rebooting) before the device could report compliance.\n- BitLocker protection was found to be suspended on the endpoint rather than absent, resulting in the compliance evaluation returning an unhealthy encryption state despite the device being online and scoped to the correct policy.\n- A stale device check-in (over 24 hours) compounded the issue by delaying the reporting of encryption status to Intune, prolonging the Conditional Access block.\n- Multiple devices across more than one office were affected simultaneously following a compliance policy rollout requiring BitLocker encryption.\n- Some devices began encryption only after a forced sync with the new compliance policy, indicating encryption had not previously been initiated on those endpoints.", "reporting": "Resolved by IT after confirming BitLocker encryption was fully active and ensuring the device reported healthy encryption attestation to Intune following a policy refresh."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:06:30.876783+00:00", "final_grade": "Accepted"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/encryption-actually-disabled-or-attestation-failed';
UPDATE wiki_pages SET curated_description = '{"title": "Intermittent Encryption Signal Loss After OS Update Causes False Noncompliance", "symptoms": "Affected users report that their corporate-managed devices are marked Noncompliant in Intune immediately following an OS update, OS upgrade, or a compliance policy change that introduces an encryption requirement. Although encryption (BitLocker on Windows, device encryption on Android) appears enabled when verified locally via Control Panel or Company Portal, the Intune compliance service does not reliably receive or retain the encryption signal. Conditional Access consequently blocks access to Microsoft 365 resources including Outlook, Teams, SharePoint Online, Exchange Online, and other Office 365 services.\n\nForced device syncs and compliance reevaluations initiated from the Intune admin console may briefly return the device to a Compliant state, but the status reverts to Noncompliant within minutes. In some cases the device''s last check-in timestamp in Intune is significantly stale—up to nine days old—meaning the compliance state never refreshes after the OS change. The intermittent or absent encryption telemetry persists across reboots and repeated Company Portal syncs performed by the affected users.\n\nThe issue has been observed on Windows 10, Windows 11, and Android 11 corporate-managed devices across multiple office locations. In all reported cases, policy scope reviews confirm that the affected devices are correctly targeted by the relevant encryption compliance policy with no duplicate or stale assignments present.", "cause": "A recent OS update or a newly tightened compliance policy left the device''s Intune management check-in state stale, preventing the BitLocker or device-encryption status from being reported back to the compliance service. Because the encryption-required compliance policy depended on that signal, back-end evaluations intermittently or persistently missed the encryption state, and Conditional Access consumed a false Noncompliant result until device telemetry and policy evaluation were refreshed and stabilized.", "variations": "- Multiple Android devices simultaneously affected after an admin-pushed compliance policy change adding an encryption requirement, rather than after an OS update\n- Device check-in timestamp in Intune stale by over a week following an OS upgrade, preventing any compliance refresh until a manual sync is forced\n- Encryption signal briefly restored after a forced compliance reevaluation from the admin console, then reverted to missing within minutes\n- Windows 10 to 21H2 feature upgrade triggering the issue, as distinct from a routine overnight patch", "reporting": "Resolved by IT after device telemetry and compliance policy evaluation were refreshed and stabilized to restore accurate encryption signal reporting."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:07:31.807350+00:00", "final_grade": "Accepted"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/encryption-telemetry-broken-after-os-or-hardware-change';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Compliance Refresh Leaves Devices Noncompliant Despite Sync Attempts", "symptoms": "Affected users report that their managed devices are marked as noncompliant in Company Portal, triggering Conditional Access blocks that prevent access to corporate resources such as Outlook email and OneDrive. The noncompliant status persists even after manual sync attempts through Company Portal, which complete without error but do not update the compliance state.\n\nOn Windows devices, the last device check-in remained stale at approximately 48 hours. A backend sync triggered by support staff registered a check-in attempt but did not cause the compliance record to refresh, indicating the device was not successfully processing compliance signals. No specific policy condition was surfaced in this scenario.\n\nOn Android devices, the noncompliance appeared following a compliance policy update and presented as an encryption-related condition tied to a specific device compliance policy. Diagnostics produced mixed findings, including inconsistent encryption reporting from the Android attestation layer and a stale policy assignment following a group membership change. These observations complicated the resolution path and required additional platform-side review by the Intune administration team before a definitive fix could be applied.\n\nAcross both platforms, the core behavior was consistent: compliance evaluation failed to complete or refresh properly, leaving devices in an indeterminate noncompliant state that blocked access to business applications through Conditional Access.", "cause": "A stale Intune MDM check-in prevented the affected devices from refreshing their compliance evaluation, leaving Conditional Access to enforce an outdated noncompliant state. Available evidence pointed to failed or incomplete compliance state refresh rather than a confirmed BitLocker or OS-version policy violation. A single root cause could not be confirmed from first-line diagnostics because the available compliance, encryption, and assignment signals were inconsistent.", "variations": "- On Android devices, some units in the affected group cleared their noncompliant status after a manual Company Portal sync, while the majority remained noncompliant and did not update promptly — indicating inconsistent compliance refresh behavior across the same device population.\n- The Android noncompliance specifically referenced an encryption-related policy condition, whereas the Windows case did not surface an encryption indicator and instead presented primarily as a stale check-in with no policy condition called out.\n- The issue affected multiple users within a single group, suggesting group-level policy targeting or group membership changes as a contributing scope factor.", "reporting": "Resolved by IT after escalation for platform-side review; reference as stale compliance refresh causing persistent noncompliant state and Conditional Access blocks."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:09:16.868311+00:00", "final_grade": "Accepted"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/indeterminate-compliance-refresh-failure';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Intune Check-In Causes Missing Encryption Signal and Noncompliance", "symptoms": "Affected users on corporate-managed devices — including Windows 10/11 laptops, macOS endpoints, iOS/iPadOS devices, and Android mobile devices — are blocked from accessing Microsoft 365 resources (Exchange Online, SharePoint, Teams, Outlook) and other Conditional Access–protected services such as corporate VPN. Azure AD Conditional Access evaluates the device as noncompliant, and users receive errors such as \"Your device is not compliant\" or \"You can''t get there from here.\" Company Portal reflects a noncompliant status with a stale last-sync timestamp.\n\nThe underlying compliance failure is a missing or unreported encryption signal in Intune. Device records show the encryption attribute as blank, unknown, \"Not Encrypted,\" \"EncryptionNotReported,\" or \"EncryptionRequired,\" even when local encryption (BitLocker, FileVault, or native device encryption) is confirmed enabled on the endpoint. The affected devices have not completed a successful Intune check-in for periods ranging from approximately 36 hours to more than 14 days, preventing the Device Compliance Service from receiving a current encryption status.\n\nManual or remote sync attempts do not always resolve the issue on the first try. In several cases, the device briefly shows as compliant in the portal after a forced sync, but Conditional Access continues to block access based on older noncompliant evaluations until a full compliance re-evaluation incorporating a fresh encryption signal completes. The issue has been observed on individual devices and in bulk — in one case affecting approximately 12–14 devices simultaneously after a compliance policy update — disrupting access during time-sensitive work. Temporary Conditional Access exemptions were applied in some instances to restore productivity while compliance state caught up.", "cause": "Affected devices had not checked in to Intune within the expected sync window, leaving the required encryption compliance signal (BitLocker, FileVault, or native device encryption) absent or stale in the device inventory. Because the compliance policy required device encryption and no current signal was available, the Device Compliance Service evaluated the devices as noncompliant. Conditional Access then enforced the noncompliant result and blocked access to protected corporate resources.", "variations": "- On macOS devices, the missing signal corresponds to FileVault; in at least one case FileVault was not yet fully enabled, requiring user-side enablement before compliance could be restored.\n- On Android devices, the stale check-in window reached up to 14 days, with encryption reported as \"Not reported\" despite all other policy conditions passing.\n- On iOS/iPadOS devices, encryption status appeared as \"unknown\" or \"not reported\" rather than explicitly failing, and in one case a scheduled compliance policy update immediately triggered the stale state.\n- Following a hardware change such as a motherboard replacement, TPM attestation data was invalidated, causing Intune to report encryption as noncompliant despite BitLocker being enabled locally.\n- BitLocker encryption was found paused after a BIOS update, preventing the encryption signal from being reported even though the device was online and connected.\n- In some cases a forced sync briefly flipped the device to compliant in Intune, but Conditional Access continued to deny access based on an older evaluation until a full re-evaluation completed.\n- After a compliance policy update, multiple devices within the same policy group became noncompliant simultaneously, with a subset requiring individual remediation because BitLocker was not enabled or had not reported status.\n- The issue affected access to non-Microsoft gated resources such as corporate VPN, depending on the organization''s Conditional Access policy scope.", "reporting": "Resolved by IT by forcing a device sync, confirming encryption enablement, and allowing a full compliance re-evaluation to restore compliant status and lift Conditional Access blocks."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:13:26.337494+00:00", "final_grade": "Accepted"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/stale-checkin-missing-encryption-signal';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Compliance Signal Mismatch Between Intune and Conditional Access", "symptoms": "Affected users on Intune-managed Windows 10 and Windows 11 corporate laptops experience access blocks to Microsoft 365 services—including Outlook, Exchange Online, Teams, and SharePoint—due to Conditional Access evaluating their devices as noncompliant. The denial typically cites a missing or absent encryption signal, even though the devices have BitLocker encryption actively enabled and verified both locally and in the Company Portal or Intune portal. The core issue is a mismatch between the compliant state reported by Intune and the stale or outdated compliance signal consumed by Conditional Access during sign-in evaluation.\n\nThe block may be persistent or intermittent, with some affected users experiencing consistent denial while others see sporadic failures across sign-in attempts. Manual sync attempts and device reboots do not immediately resolve the discrepancy, as the stale compliance data continues to be referenced during token evaluation. In at least one case, the Intune service-side compliance record itself reflected a noncompliant encryption signal despite the endpoint''s local encryption state being healthy, with BitLocker protection on and a TPM key protector present.\n\nThe issue affects both remote workers and users connecting from office locations and is not tied to a specific network or IP range. Affected users are unable to perform normal work—including email, collaboration, and document access—until the stale compliance state is cleared and refreshed telemetry propagates to the Conditional Access evaluation layer. Sign-in logs confirm access denials with device-noncompliant error codes during the period of misalignment.", "cause": "Conditional Access consumed a stale or delayed device compliance signal for BitLocker encryption while Intune already showed the device as compliant. The encryption state had not fully propagated to the Conditional Access evaluation path, creating a temporary mismatch between Intune compliance status and access enforcement. The stale noncompliant signal continued to be used for token evaluation until the compliance record was refreshed and cache propagation completed.", "variations": "- In one case, Intune itself displayed a noncompliant signal for the encryption requirement even though the local device state confirmed BitLocker was active with a TPM key protector, suggesting the staleness extended to the Intune compliance record rather than only the Conditional Access cache.\n- Some affected users experienced fully persistent access blocks, while others saw intermittent denials where sign-in attempts alternated between success and failure.\n- One instance involved a Windows 11 22H2 device rather than Windows 10 21H2, indicating the issue is not limited to a single operating system version.\n- In certain cases, temporary Conditional Access exclusion groups or grace windows were applied to restore user productivity while the compliance signal propagation completed.", "reporting": "Resolved by IT after the stale device compliance signal was refreshed and propagation between Intune and Conditional Access completed, restoring normal access evaluation."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:14:06.664738+00:00", "final_grade": "Accepted"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/stale-compliance-state-mismatch-ca-cache';
UPDATE wiki_pages SET curated_description = '{"title": "Deprecated Compliance Policy Reference Causes False Encryption Noncompliance", "symptoms": "Affected users with Intune-managed devices were blocked from accessing corporate resources — including Exchange Online, SharePoint Online, Microsoft Teams, Outlook, and OneDrive — by Conditional Access enforcement after compliance policy consolidation or baseline refresh activities. The Intune admin console and Company Portal reported encryption signals as missing (e.g., \"EncryptionMissing\" or \"Not reported\"), even though BitLocker or device-level encryption was confirmed as fully enabled on most affected endpoints. The issue impacted Windows 10, Windows 11, and Android devices across multiple offices and security groups.\n\nInvestigation revealed that affected devices were still evaluating against deprecated or retired compliance policy revisions rather than the current replacement versions. Stale device check-in timestamps meant compliance had not been re-evaluated since the policy change, causing encryption telemetry mappings to fail and Conditional Access to deny access based on outdated compliance state. The noncompliant status persisted through repeated manual sync attempts and remote sync operations, though some devices returned to compliant status after syncing while others required administrative correction of the underlying policy reference.\n\nIn at least one case, the missing encryption signal reflected a genuine device state — BitLocker had stalled after an OS update and was not fully enabled — distinguishing that instance from the more common false-reporting pattern. The issue typically affected groups of users tied to specific security or device groups whose policy assignments still pointed to the deprecated policy version.", "cause": "Deprecated Intune compliance policies remained assigned to device groups through stale group mappings after policy consolidation. Affected devices continued evaluating against the retired policy revisions, which did not include the current encryption requirement or signal mapping. Stale device check-in status further delayed receipt of corrected policy assignments and updated compliance evaluations.", "variations": "- Android devices in the same security group were affected alongside Windows endpoints, with identical Conditional Access blocks on corporate resource access.\n- On Android 11 devices, Company Portal showed encryption status as \"Not reported\" even though device-level encryption was confirmed enabled at the OS level.\n- In one case, BitLocker had stalled after an OS update and was not fully enabled, meaning the missing encryption signal reflected an actual device state rather than a telemetry reporting gap.\n- Some devices had pending Windows cumulative updates that acted as a secondary blocker to restoring compliance even after the policy reference was corrected.\n- Remote and traveling users experienced extended periods of noncompliance due to prolonged gaps between Intune check-ins, resulting in especially stale compliance evaluations.\n- Some affected users experienced intermittent partial restoration of access to individual services (e.g., Outlook) after a manual sync, while other services (e.g., OneDrive Mobile) remained blocked.\n- In one group, the stale reference pointed to a retired policy scope associated with a legacy assignment group rather than simply an outdated policy version.\n- Mobile device access (e.g., Outlook on a personal phone) remained unaffected, with Conditional Access blocks limited to managed endpoints evaluating against the deprecated policy.", "reporting": "The issue was resolved by IT after removing deprecated compliance policy assignments and ensuring affected devices re-evaluated against the current policy revision."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:16:15.834415+00:00", "final_grade": "Accepted"}' WHERE family = 'DCP' AND root_cause_id = 'DCP/stale-deprecated-compliance-policy-reference';
UPDATE wiki_pages SET curated_description = '{"title": "Missing or Incorrect Conditional Forwarder on Internal DNS Resolver", "symptoms": "Affected users experience intermittent DNS resolution failures when looking up internal hostnames through specific corporate resolvers. Queries return NXDOMAIN, SERVFAIL, or time out, while the same records resolve successfully against the authoritative internal DNS servers or from other subnets and office locations. Direct access to services by IP address succeeds in all cases, confirming that underlying applications and network paths are healthy. The failures disrupt internal dashboards, authentication endpoints, API gateways, CI/CD pipelines, automated deployments, and service-discovery workflows, often initially appearing to be application outages rather than DNS issues.\n\nThe inconsistency is resolver-specific and often subnet-specific: one internal recursive resolver returns correct results while another serving a different subnet or site returns negative or stale responses for the same hostname. In some cases, a public resolver returns a valid address while corporate resolvers fail. Affected users in multiple offices may observe different failure modes simultaneously — some receiving NXDOMAIN, others experiencing timeouts or stale A records pointing to outdated IP addresses — contributing to confusion about the scope of the outage.\n\nThe root cause is a missing, outdated, or partially incorrect conditional forwarder configuration on the affected resolver. The forwarder may be absent entirely, may reference a decommissioned upstream server, or may inconsistently forward the internal zone. Stale negative-cache entries compound the problem, causing the resolver to continue serving incorrect responses even after authoritative zone data is correct. Once forwarder targets are corrected and resolver caches flushed, name resolution returns to normal across affected hosts and subnets.", "cause": "One or more internal DNS resolvers had a missing, outdated, or incorrectly configured conditional forwarder for the affected internal zone. This caused queries to be routed incorrectly — returning NXDOMAIN, SERVFAIL, timeouts, or stale cached records — while other resolvers with correct forwarder configurations continued to return the authoritative answer. Stale negative-cache entries on affected resolvers perpetuated the failures until both the forwarder configuration and cache state were corrected.", "variations": "- In some cases the resolver round-robins between a valid and a decommissioned forwarder target, causing approximately 20–30% of queries to fail while the remainder succeed, producing partial rather than total resolution failure.\n- Certain incidents present with stale cached IP addresses (resolving to an older, incorrect IP) rather than NXDOMAIN, causing connections to fail silently against the old endpoint.\n- A cache flush alone may not resolve the issue if the stale or missing forwarder entry remains in place, as the resolver re-caches negative responses on subsequent queries to the dead target.\n- The failure may affect multiple internal zones or hostnames simultaneously when the conditional forwarder covers a parent domain, broadening the blast radius beyond a single service record.\n- Cross-site impact has been observed when multiple office locations share the same misconfigured resolver instance, causing geographically dispersed users to report identical symptoms independently.\n- SERVFAIL spikes were observed in network monitoring during the resolution failure window, correlating with the resolver misconfiguration.\n- Automated deployments and CI/CD pipelines were blocked in one incident due to intermittent NXDOMAIN responses for an internal service hostname.\n- The issue may emerge following scheduled DNS record updates or maintenance windows, with certain resolvers continuing to serve outdated or negative responses after authoritative zone data has been corrected.", "reporting": "Resolved by IT after correcting the conditional forwarder configuration on the affected internal DNS resolvers and flushing stale cached entries."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:19:28.625965+00:00", "final_grade": "Accepted"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/missing-or-incorrect-conditional-forwarder';
UPDATE wiki_pages SET curated_description = '{"title": "Client-Side DNS Cache or Local Network Condition Causing Resolution Failures", "symptoms": "Affected users in a corporate office environment reported intermittent DNS resolution failures when attempting to reach internal services by hostname. The issue manifested as NXDOMAIN responses or resolution to outdated IP addresses belonging to decommissioned hosts, even though other systems on the same network were resolving the same hostnames successfully. The problem primarily impacted access to internal endpoints such as service-discovery and application dependency registries.\n\nInvestigation confirmed that both authoritative DNS servers and corporate resolvers were returning correct, current records for the affected hostnames. The inconsistency between working and non-working systems pointed to endpoint-local conditions rather than a centralized DNS infrastructure fault. One affected workstation was found returning a stale cached IP address that had already been corrected in the authoritative zone during a prior change window, while another received NXDOMAIN responses despite correct zone data being present on the servers.\n\nThe issue was most visible on clients that had recently changed networks or resumed from long-running sessions. In the reported cases, resolution returned to normal after affected users flushed their local DNS caches or reconnected to the office VPN, consistent with a transient or client-side caching condition rather than a server-side fault.", "cause": "No fault was found in the central internal DNS service. Client-side DNS caching, local network settings, or an already-cleared transient condition caused the earlier hostname resolution failures. The issue was isolated to individual endpoints rather than the shared resolver or authoritative infrastructure.", "variations": "- One affected endpoint resolved an internal hostname to an outdated IP address associated with a previously decommissioned host, suggesting a stale local cache entry persisting beyond the authoritative zone correction.\n- The issue cleared on one system only after the user reconnected to the corporate VPN, indicating that a network transition may have left the client with an unusable or outdated resolver configuration.", "reporting": "Resolved by IT; intermittent internal DNS resolution failures traced to client-side caching or local network conditions with no centralized DNS fault identified."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:20:11.415206+00:00", "final_grade": "Accepted"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/no-server-side-fault-client-side-or-transient';
UPDATE wiki_pages SET curated_description = '{"title": "Inconsistent Internal Resolver Cache or Forwarder State After DNS Maintenance", "symptoms": "Affected users experience intermittent failures when resolving internal hostnames used by critical services such as database endpoints and backend application dependencies. Failures manifest as a mix of NXDOMAIN responses, SERVFAIL errors, and DNS lookup timeouts when querying internal resolvers. In some cases, lookups return stale A records pointing to outdated IP addresses rather than the current expected address. These resolution failures prevent name-based connectivity to internal services, causing deployment pipeline failures, application errors, and loss of access to internal tools.\n\nThe issue presents non-uniformly across clients, subnets, and office locations. Hosts on one internal subnet or resolver path may experience consistent failures while hosts on a different subnet return correct results. Even within the same environment, the failure mode varies — some clients receive NXDOMAIN, others experience timeouts, and others receive outdated records — depending on which internal resolver or cache instance handles the query. Reports have spanned multiple racks within a single datacenter as well as multiple office locations.\n\nIn reported cases, symptom onset correlated with recent DNS maintenance windows or zone migrations. Authoritative DNS servers responded correctly when queried directly, while the caching or forwarding resolvers serving affected clients returned inconsistent or incorrect answers. The exact resolver failure mode was not always conclusively isolated, as post-cache-flush behavior sometimes remained inconsistent and forwarder configuration could not be fully confirmed from available evidence.", "cause": "Intermittent internal DNS resolution failures were caused by stale or inconsistent data held by caching and forwarding resolvers following DNS maintenance or zone migrations. The resolver layer served outdated or incorrect answers for internal zones even though authoritative records were healthy, with the inconsistency affecting multiple subnets and regions. Misconfiguration or instability in the corporate resolver path compounded the issue, producing mixed NXDOMAIN, SERVFAIL, and stale-record responses across different resolver instances.", "variations": "- Some affected hosts returned stale A records pointing to a previous IP address following a recent endpoint migration, rather than returning an error\n- Failures appeared only after a scheduled DNS maintenance window, with no symptoms reported prior to the change\n- Approximately 40% of queries from a specific host returned NXDOMAIN while the remaining queries succeeded, indicating intermittent rather than total failure\n- Change log evidence on the primary DNS server was unavailable due to log rotation, preventing full confirmation of authoritative record drift\n- One resolver intermittently returned SERVFAIL for internal zone queries while authoritative servers responded correctly, but the exact failure mode could not be conclusively isolated even after cache flush", "reporting": "Resolved by IT; reference as intermittent internal DNS resolution failures due to inconsistent resolver cache or forwarder state following DNS maintenance."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:21:21.455998+00:00", "final_grade": "Accepted"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/resolver-path-inconsistency-mixed-cause';
UPDATE wiki_pages SET curated_description = '{"title": "Stale A Record in Authoritative Internal DNS Zone", "symptoms": "Affected users and internal services experience intermittent failures resolving internal hostnames — such as application endpoints, database services, and portal resources — across multiple subnets, VLANs, and office locations. DNS queries return inconsistent results: some yield an outdated IP address belonging to a decommissioned or migrated host, while others return NXDOMAIN. The mixed responses disrupt application-layer connectivity, causing health-check failures, connection timeouts, broken deployment pipelines, and degraded user-facing dashboards.\n\nThe issue traces to stale or incorrect A record data persisting in the authoritative internal DNS zone after a planned infrastructure change such as a service migration or host decommissioning. In some cases the authoritative zone itself retains the outdated or duplicate record; in others the zone is correctly updated but recursive resolvers continue serving cached stale data due to high TTL values or negative cache entries. Both scenarios produce the same observable pattern of alternating stale-address and NXDOMAIN responses across the resolver tier.\n\nThe problem typically surfaces shortly after a planned DNS or infrastructure change and is reported concurrently by engineering, operations, and application teams. Internal monitoring dashboards corroborate the issue with elevated DNS error rates and NXDOMAIN spikes. Contributing factors include deprecated DNS management or change-control policy references in zone or resolver configurations, zone serial numbers not incremented after record changes, and resolver caches not flushed following authoritative updates.", "cause": "A stale A record remained in the internal authoritative DNS zone after a service IP change or host decommissioning, and recursive resolvers continued serving outdated cached data due to high TTL values or unflushed caches. In some cases, deprecated DNS management policy references in resolver or zone configurations further delayed detection and correction of the outdated zone data.", "variations": "- In some cases the authoritative zone already contained the correct record, but resolvers continued serving stale cached data due to an outdated policy reference in the resolver configuration, requiring a configuration update and service restart rather than a zone record correction.\n- Deprecated DNS change-control or zone management policy references delayed remediation or contributed to resolver misconfiguration.\n- Some affected environments returned purely NXDOMAIN from one resolver while a secondary resolver returned the correct address, rather than alternating between a stale IP and NXDOMAIN.\n- Some clients experienced DNS query timeouts or SERVFAIL responses rather than explicit NXDOMAIN, particularly when multiple resolver nodes held conflicting cache states.\n- In certain cases only application server hosts were affected, surfacing the issue through health-check failures and broken database connectivity rather than user-reported browsing problems.\n- Duplicate stale A records were left behind in the authoritative zone after a migration rather than the existing record being updated, causing the resolver to serve the retired address.\n- The issue affected multiple distinct hostnames within the same internal zone simultaneously rather than a single record.\n- High TTL values on the affected zone records prolonged the period during which stale data was served, extending the window of user impact beyond typical cache refresh cycles.", "reporting": "Resolved by IT after correcting the stale authoritative zone A record, flushing resolver caches, and updating deprecated DNS policy references."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:23:30.380790+00:00", "final_grade": "Accepted"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/stale-authoritative-zone-record';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Resolver Cache Serving Outdated Records After Internal Zone Update", "symptoms": "After an internal DNS zone record change — such as an A record update during a service or infrastructure migration — affected users and dependent services experience intermittent name-resolution failures for internal hostnames. Lookups against corporate recursive resolvers return a mix of outdated A records (pointing to previous or decommissioned IP addresses), NXDOMAIN errors, SERVFAIL responses, and timeouts, even though the authoritative DNS servers already reflect the correct, updated entry. Direct IP connectivity to the target service remains functional, confirming the issue is confined to DNS name resolution.\n\nThe behavior is resolver-specific: one resolver in the environment may return the expected record while another continues to serve stale cached data, causing inconsistent results depending on which resolver handles a given query. Some clients observe correct and incorrect answers alternating on repeated lookups. The inconsistency typically spans multiple subnets, office locations, or datacenter segments served by overlapping resolver infrastructure, creating partial-outage conditions.\n\nThe impact extends beyond individual users to CI/CD pipelines, automated service-to-service communication, health-check and monitoring systems, internal service registries, and any system relying on hostname-based lookups. Investigation consistently reveals a mismatch between cached entries on one or more recursive resolvers and the current authoritative zone data, with resolver cache metadata showing entries last refreshed before the zone update. In some cases, resolver latency spikes and timeouts of 30–60 seconds accompany the stale responses.", "cause": "Internal DNS recursive resolvers retained stale cached A records after the authoritative internal zone was updated, continuing to serve outdated or negative-cached responses instead of fetching the current record. High TTL values on the original cached entries prevented resolvers from re-fetching the updated record within a reasonable window after the change, prolonging the staleness period.", "variations": "- Some resolvers return NXDOMAIN or SERVFAIL rather than a stale A record, particularly when the resolver holds a cached negative response from a brief zone transfer hiccup.\n- Caching forwarders downstream of the primary resolver continue serving stale data even after the primary resolver cache has been cleared, requiring independent cache flushes on each downstream node.\n- A resolver fails to honor TTL refresh behavior correctly, requiring a full service restart rather than a simple cache flush to begin returning current records.\n- Records with very high TTL values (e.g., 86400 seconds) tied to decommissioned hosts persist in resolver caches long after the zone has been updated.\n- Some clients observe a mix of correct and incorrect responses on repeated queries, with stale answers appearing intermittently rather than consistently.\n- The stale resolution issue spans multiple office locations and datacenter segments when those sites share overlapping resolver infrastructure.\n- An aggressive caching policy or long-running resolver process (without restart) prevents cache entries from being refreshed on schedule.\n- Automated health checks, monitoring platforms, and dependent service registries co-report the resolution failures alongside end-user reports.", "reporting": "Resolved by IT flushing stale cache entries on affected internal resolver infrastructure and, where necessary, reloading the authoritative zone or restarting the resolver service, after which lookups returned the correct authoritative address and application connectivity was restored."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:29:29.195566+00:00", "final_grade": "Accepted"}' WHERE family = 'DRF' AND root_cause_id = 'DRF/stale-resolver-cache-after-record-change';
UPDATE wiki_pages SET curated_description = '{"title": "BitLocker Not Initialized on Endpoint Preventing Recovery Key Escrow", "symptoms": "Affected users operate corporate-managed Windows 10 laptops that are flagged as noncompliant for disk encryption in Intune. In each case, the management console reports encryption as not enabled on the device, and no BitLocker recovery key is visible in Azure AD or tenant escrow for the associated user account. This noncompliant status prevents the devices from meeting organizational endpoint encryption requirements for normal corporate use.\n\nFor two of the three reported cases, the initial intake established only that encryption was not enabled and no recovery key was present, without confirming whether the BitLocker enablement prompt had ever been presented to or acted upon by the user; the underlying cause of the missing encryption remained undetermined at triage. In the remaining case, the affected user specifically reported having accepted the BitLocker enablement prompt approximately two weeks prior, but encryption never progressed — the drive icon never displayed a lock symbol, no completion notification appeared, and the device continued to report as unencrypted in Intune.\n\nAcross all three tickets, initial reports lacked sufficient device-level detail to confirm the underlying cause of the encryption failure. This limited the ability to validate policy delivery, TPM readiness, or key escrow status at the time of intake.", "cause": "BitLocker was not fully initialized on the affected endpoints, so no valid recovery key had been escrowed to Azure AD or Intune. The most likely contributing conditions were missing or unapplied Intune BitLocker policy and unverified TPM/protector readiness, which left devices reporting encryption as disabled and therefore noncompliant, though TPM initialization, policy application, and escrow sync state could not be fully confirmed from the available evidence.", "variations": "- In one case, the affected user confirmed having accepted the BitLocker enablement prompt approximately two weeks before filing the ticket, with no subsequent encryption progress observed on the device during that interval.\n- One ticket was submitted on behalf of the affected user by a third party via email rather than by the user directly.\n- In one instance, the affected device was associated with a specific business group (Finance), and the noncompliance was identified under that group''s enrollment context.", "reporting": "Escalated to IT for investigation into incomplete BitLocker enablement conditions including policy application and TPM/protector readiness; resolution outcome was not documented in the available ticket evidence."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:30:50.500193+00:00", "final_grade": "Accepted"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/inconclusive-evidence-bitlocker-not-fully-enabled';
UPDATE wiki_pages SET curated_description = '{"title": "Deprecated Intune Encryption Policy Prevents BitLocker Activation and Key Escrow", "symptoms": "Affected users with corporate-managed Windows 10 or Windows 11 devices report that BitLocker disk encryption does not activate following Intune enrollment. The devices appear as noncompliant for encryption in Company Portal and Intune compliance dashboards, and in most cases no recovery key is visible in the management portal. Investigation consistently reveals that the affected devices are assigned to a deprecated or legacy encryption policy rather than the current active policy version, preventing the encryption configuration from being applied or enforced.\n\nThe TPM protector and key escrow state varied across affected devices. Some devices showed the TPM as not initialized, others had the TPM protector present but encryption protection still disabled, and in one case no key protectors were found at all. Where the TPM was uninitialized, encryption could not start and recovery key escrow failed entirely. Where the TPM protector existed but the policy was stale, conflicting telemetry arose — Intune reported noncompliance while a recovery key appeared escrowed in the tenant, yet local status showed protection off. In one case, a TPM initialization error was observed during an earlier provisioning attempt, though the TPM was later confirmed functional.\n\nThe issue affected devices across multiple offices and user groups. Affected users were unable to meet endpoint security compliance requirements, which blocked access to corporate resources or created gaps in recovery-key visibility for IT administrators. Other laptops within the same device groups were confirmed unaffected.", "cause": "A deprecated or stale Intune Endpoint Encryption Policy reference remained associated with the affected devices, preventing the current active encryption policy from being received and applied. Without the correct policy, the TPM protector was not properly initialized or enforced, BitLocker encryption did not start, and recovery key escrow to the management service failed.", "variations": "- One device was inadvertently excluded from its intended device group during onboarding, resulting in no encryption policy assignment rather than a stale one.\n- One case exhibited conflicting telemetry: Intune showed encryption noncompliance while a recovery key was already escrowed in the tenant and the TPM protector existed locally, indicating partial but unenforced policy application.\n- One device had no key protectors at all on the encrypted volume, with local status returning protection off and no protectors found.\n- One ticket was raised by the affected user''s manager rather than the user themselves, due to an upcoming client visit requiring compliance.\n- One device had not completed an MDM sync since before the most recent policy rollout, compounding the stale policy assignment.\n- A TPM initialization error was initially observed during an earlier provisioning attempt, though the TPM was subsequently found to be present and initialized.\n- Peer devices in the same assigned group were confirmed unaffected and did not display the noncompliant encryption status.", "reporting": "Resolved by IT; reference: deprecated or stale Intune encryption policy association preventing BitLocker activation and recovery key escrow."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:34:33.434820+00:00", "final_grade": "Accepted"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/intune-policy-not-assigned-or-stale-deprecated-policy';
UPDATE wiki_pages SET curated_description = '{"title": "BitLocker Enabled Locally but Intune Reports Noncompliant Due to Escrow and Compliance Reporting Desynchronization", "symptoms": "Affected users with managed Windows 10 laptops — including at least one Surface Laptop 4 — report that BitLocker disk encryption is confirmed as fully enabled locally on the OS volume, yet Microsoft Intune continues to display the device as noncompliant with an \"EncryptionNotEnabled\" status. Recovery keys are not visible in Azure AD or Intune escrow, preventing support teams from confirming key availability and leaving the devices in a blocked compliance state. In each case, the local endpoint shows BitLocker active on the system drive with encryption complete, but the management console does not reflect this.\n\nThe underlying causes documented across these tickets differ. In one case, Azure AD confirmed a recovery key escrow event, but the Intune compliance service backend continued to report the device as not encrypted — a reporting synchronization mismatch that persisted after all endpoint-side remediation was confirmed complete and required escalation to the backend compliance service team. In a second case, local BitLocker was active but the key protector configuration was incomplete: manage-bde output revealed only a Numerical Password protector with no TPM protector bound, explaining why Intune still reported the device as unencrypted. In a third case, the device had a valid TPM 2.0 protector and full local encryption, but the recovery key failed to escrow because the device encountered an MDM sync error (0x80180014) during its last several scheduled check-ins, preventing the compliance state from updating.\n\nDespite differing technical causes, the user-facing presentation is consistent: Intune shows noncompliant encryption status, recovery keys are absent from the management portal, and affected devices are flagged during compliance reviews.", "cause": "Three distinct root causes were identified across affected devices. First, a backend compliance reporting desync occurred where Azure AD had successfully received a recovery key escrow event, yet the Intune compliance service continued to report the device as not encrypted — a mismatch between backend services rather than an endpoint-side failure. Second, BitLocker activated before the management state had fully reconciled, resulting in an incomplete protector configuration: the TPM protector binding was never established, leaving only a Numerical Password protector, which caused Intune to treat the device as noncompliant. Third, an MDM sync error (0x80180014) prevented the device from communicating with Intune across multiple consecutive check-ins, blocking recovery key escrow to Azure AD entirely and leaving the compliance state stale.", "variations": "- In one case, the Intune compliance backend continued to report \"NotEncrypted\" even after Azure AD confirmed a successful recovery key escrow event, indicating a backend reporting desync rather than an endpoint-side issue.\n- One affected device (Surface Laptop 4) had BitLocker enabled locally but lacked a TPM protector binding, with only a Numerical Password protector present, representing a protector initialization gap.\n- One device logged MDM sync error 0x80180014 across multiple consecutive scheduled check-ins, directly preventing recovery key escrow to Azure AD.\n- In one case, the Company Portal app explicitly displayed a \"last sync failed\" status to the affected user.", "reporting": "Resolved by IT through backend compliance service escalation, protector re-initialization, or MDM sync remediation depending on the underlying cause; reference \"BitLocker escrow and compliance reporting desynchronization\" when reporting."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:36:51.576459+00:00", "final_grade": "Accepted"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/mdm-sync-failure-causing-state-desync';
UPDATE wiki_pages SET curated_description = '{"title": "Recovery Key Escrow Failure Leaves Device Noncompliant Despite Healthy TPM", "symptoms": "Affected users with Intune-managed Windows 10 corporate endpoints experience a persistent noncompliant encryption state in the Device Compliance Service or Company Portal, despite having a functional TPM 2.0 module and a correctly assigned BitLocker encryption policy. The core issue is that the BitLocker recovery key fails to escrow to Azure AD or Intune during or after the encryption process, leaving the recovery key absent from the cloud device record. Without a successfully escrowed key, the compliance service does not recognize the device as meeting corporate encryption requirements.\n\nThe failure manifests at different points in the device lifecycle. In some cases, the recovery key backup fails during initial enrollment; in others it occurs after a subsequent policy push on an already-enrolled device. Affected devices may display BitLocker protection as suspended, show BitLocker as not enabled in Windows Settings, or appear to have BitLocker components present locally while no key is visible in the management tenant. In at least one instance, BitLocker was confirmed entirely inactive on the system drive with no protectors found, meaning encryption had never been initiated despite correct policy assignment.\n\nIn all scenarios, the Company Portal compliance tile continues to report disk encryption as noncompliant, and affected users are unable to self-resolve the issue through manual sync attempts. The compliance block prevents affected users from meeting corporate endpoint encryption baselines and can restrict access to organizational resources. The issue has been observed across different business groups and office locations.", "cause": "BitLocker recovery key escrow failed or never completed during MDM enrollment or subsequent policy processing, leaving the device with a local protector present (or BitLocker still suspended) but no recovery key recorded in the management service. Errors such as key protection service failures, access-denied responses, or transient escrow timeouts prevented the recovery key from being uploaded to Azure AD or Intune, causing the cloud compliance state to remain out of sync with local encryption status.", "variations": "- Recovery key backup fails during initial Intune enrollment with error code 0x87D1FDE8 (KeyBackupError).\n- Recovery key escrow upload fails with error code 0x80090010 recorded in MDM/BitLocker event logs after BitLocker is started locally.\n- Recovery key escrow fails with access-denied error 0x80070005 despite a valid TPM protector and corporate account enrollment.\n- An escrow upload timeout (BitLocker-API Event ID 846) occurs before TPM protector initialization completes, resulting in a timing mismatch between local encryption state and cloud compliance status.\n- BitLocker protection shows as suspended on the OS drive rather than disabled, yet the device is still flagged noncompliant due to the missing escrowed key.\n- Compliance remains noncompliant even after a local TPM protector initialization and Intune sync because the recovery key escrow step itself has not succeeded.\n- BitLocker components appear present locally but the escrow gap cannot be definitively attributed to either an endpoint failure or a management-side reporting delay.\n- BitLocker is confirmed entirely inactive on the system drive with no protectors found, meaning encryption was never initiated despite correct policy assignment.", "reporting": "Resolved by IT after reprocessing encryption policy, rotating the recovery key, and confirming successful escrow to the management tenant."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:39:12.527060+00:00", "final_grade": "Accepted"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/recovery-key-escrow-failure-despite-healthy-tpm-and-policy';
UPDATE wiki_pages SET curated_description = '{"title": "Uninitialized TPM Protector Prevents BitLocker Encryption and Recovery Key Escrow", "symptoms": "Affected users on corporate-managed Windows 10 and Windows 11 laptops report that their devices are flagged as noncompliant for disk encryption in Microsoft Intune, Company Portal, or the Device Compliance Service. BitLocker remains in a \"Protection Off\" state on the system drive with no key protectors configured, and no recovery key is visible in Azure AD or the Intune escrow portal. The noncompliant state blocks access to compliance-gated corporate resources such as VPN, email, SharePoint, and line-of-business applications.\n\nInvestigation consistently reveals that the TPM protector was never initialized on the affected endpoint. Although the TPM hardware is physically present and may report as ready in the management console, protector initialization did not complete during provisioning, Autopilot enrollment, or reimaging. Without an initialized TPM protector, BitLocker cannot create key protectors on the OS volume, and no recovery key is generated or escrowed to Azure AD. The Intune encryption policy is typically confirmed as correctly assigned, indicating the failure is a local TPM prerequisite issue — though in some cases the device was also missing from the required Azure AD security group or lacked the policy assignment after re-enrollment, compounding the problem.\n\nThe condition has been observed following reimaging without a TPM initialization step, motherboard replacements that invalidate a previously initialized protector, and Autopilot provisioning flows where TPM initialization was skipped. Affected users report never receiving a BitLocker PIN prompt or encryption setup during provisioning. Manual remediation attempts such as rebooting, forcing an Intune sync, or enabling BitLocker through the control panel do not resolve the issue. Even after the TPM protector is initialized and encryption starts, automatic recovery key escrow may fail intermittently across several MDM sync cycles before succeeding.", "cause": "The TPM protector was not initialized on the affected endpoint, preventing BitLocker from creating the required TPM-backed protector on the OS volume. Without this protector, encryption could not start and recovery key escrow to Azure AD or Intune could not complete. In some cases, the Intune BitLocker policy was also not assigned or had not successfully applied, further compounding the failure.", "variations": "- The Intune device compliance status intermittently toggles between noncompliant and pending despite encryption remaining off locally.\n- The TPM management console reports a specific initialization error (e.g., 0x80070057 or 0xC0000200) rather than simply showing the protector as uninitialized.\n- Recovery key escrow to Azure AD fails with a timeout error or a \"KeyPackage not found\" error after the TPM protector is initialized, requiring a forced manual backup.\n- The device was not added to the required Azure AD security group or lacked the Intune encryption policy assignment after re-enrollment or reimaging.\n- The TPM protector was previously initialized but became invalidated after a motherboard replacement, causing a formerly encrypted device to lose compliant status.\n- The device was provisioned through Windows Autopilot and the TPM protector initialization step was skipped during the automated flow.\n- An MDM sync or enrollment token error (e.g., 0x80180014 or 0x80180026) is logged alongside the escrow failure.\n- The BitLocker management UI displayed the \"Turn on BitLocker\" option as greyed out, preventing the user from enabling encryption manually.", "reporting": "Resolved by IT through TPM protector initialization, BitLocker encryption enablement, and recovery key escrow verification to Azure AD."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:42:30.784569+00:00", "final_grade": "Accepted"}' WHERE family = 'EDE' AND root_cause_id = 'EDE/tpm-protector-not-initialized';
UPDATE wiki_pages SET curated_description = '{"title": "Endpoint Protection Scan Backlog Causing Post-Login CPU Saturation", "symptoms": "Affected users on managed Windows 10 laptops experience severe slowness immediately after sign-in, with CPU utilization sustained at 80–100% and disk I/O frequently reaching near-maximum levels for several minutes. The Antimalware Service Executable (MsMpEng.exe) or a comparable endpoint protection process consistently appears as the dominant CPU consumer in Task Manager. Core productivity applications — including Outlook, Teams, Chrome, Edge, Excel, Word, File Explorer, and line-of-business tools — take anywhere from 10 seconds to over five minutes to open or become responsive. Users report loud continuous fan activity, and in some cases brief periods of complete system unresponsiveness. The slowdown recurs across reboots and is not resolved by restarting the device.\n\nInvestigation reveals a backlog of queued endpoint protection scans — ranging from a handful of deferred jobs to hundreds or thousands of pending items — that trigger simultaneously at user login. The backlogs typically accumulate after a group policy or endpoint management policy refresh that altered scan scheduling, or after missed scan windows while devices were offline. Multiple resource-heavy startup items (such as cloud-sync clients, Teams auto-launch, updater services, and endpoint management agents) launch concurrently, compounding the CPU and disk contention during the same post-login window.\n\nLow free disk space on the system drive is a consistent aggravating factor, with affected devices showing as little as 2–19 GB free on 256 GB drives. The constrained storage increases I/O contention and swap activity during the already resource-intensive startup period. Once the scan backlog is cleared and contributing factors are addressed, CPU usage drops to normal levels within minutes and application responsiveness returns.", "cause": "A backlog of endpoint protection scans — typically accumulated after a policy refresh or missed scan windows — triggered at user login alongside multiple resource-heavy startup applications, causing sustained CPU and disk I/O contention. Low free disk space on the system drive further amplified the performance degradation by increasing storage pressure during the post-login window.", "variations": "- Scan backlog size varied widely across devices, from a handful of deferred full scans to approximately 200 pending items or over 14,000 queued scan entries.\n- In some cases the endpoint protection product was CrowdStrike Falcon rather than Microsoft Defender, with the same pattern of queued scans triggering at login.\n- Free disk space ranged from critically low (approximately 2–3 GB) to moderately constrained (around 19 GB) on 256 GB drives, with lower availability correlating to more severe slowdowns.\n- Some devices had up to 14 active startup items — including policy-pushed agents, duplicate helper processes, and legacy updater services — loading concurrently at sign-in.\n- At least one affected device experienced brief full unresponsiveness rather than just slowness, with disk queue lengths averaging above four during peak contention.\n- In several cases the issue recurred after a prior partial remediation, with the scan backlog re-accumulating because underlying scan scheduling or startup policies had not been permanently corrected.\n- Application impact extended beyond standard productivity tools to include engineering build tools and CRM or line-of-business applications on some devices.\n- Inconsistent policy deployment was observed in at least one instance, where a colleague with an identical laptop model was unaffected because the corrected startup policy had been applied to that device.", "reporting": "Resolved by IT; endpoint protection scan backlog cleared and startup/scan policies adjusted to eliminate post-login CPU saturation."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:51:43.595764+00:00", "final_grade": "Accepted"}' WHERE family = 'LPD' AND root_cause_id = 'LPD/endpoint-scan-backlog-startup-disk-contention';
UPDATE wiki_pages SET curated_description = '{"title": "Post-Login Laptop Sluggishness Due to Temp File Disk Exhaustion", "symptoms": "Affected users experience consistent sluggishness on their managed Windows 10 laptop during the post-login period. Core applications such as Outlook, Chrome, and File Explorer take noticeably longer than normal to open in the first several minutes after sign-in, and general desktop responsiveness is degraded. No single application failure is identified; rather, the slowdown is broad and affects routine work across multiple programs.\n\nThe underlying issue is an accumulation of temporary files consuming a significant portion of the system drive''s available space. In reported cases, tens of gigabytes of temp files had built up in user-profile and system temp directories, leaving the drive critically low on free space. This disk-space exhaustion produces elevated CPU and disk utilization immediately after login, which subsides only partially and continues to impair application launch times until the temp-file buildup is addressed.", "cause": "Critically low available disk space combined with excessive temporary file accumulation caused ongoing disk contention and degraded laptop performance after login.", "variations": "- Affected users may initially correlate the onset of sluggishness with a recent company update push, though diagnostics confirm the root cause is disk-space exhaustion from temp-file accumulation rather than an update- or policy-related issue.\n- The slowdown presents as a general performance degradation with no single failing application, making it difficult for the affected user to pinpoint the source of the problem.", "reporting": "Resolved by IT after identifying and clearing accumulated temporary files that had exhausted available disk space on the affected laptop."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:52:39.272899+00:00", "final_grade": "Accepted"}' WHERE family = 'LPD' AND root_cause_id = 'LPD/low-disk-temp-file-accumulation';
UPDATE wiki_pages SET curated_description = '{"title": "Post-Login CPU Contention From Resource-Heavy Startup Policy Deployment", "symptoms": "Affected users with managed Windows 10 corporate laptops report significant slowness immediately after signing in. CPU usage rapidly climbs to 70–90% within one to two minutes of login, and common productivity applications — including Outlook, Chrome, Teams, Edge, and Windows Explorer — take 20–60 seconds to open. Desktop interaction is noticeably delayed during the startup window, and normal post-login work is disrupted for several minutes before performance gradually improves. The issue is confined to individual endpoints rather than the broader network.\n\nDiagnostic review of affected devices reveals multiple resource-intensive processes competing for CPU cycles during the login phase, including endpoint management extensions, scheduled policy-enforcement tasks, asset inventory agents, synchronization triggers, and telemetry collectors — all launched simultaneously as part of the updated startup configuration. In some cases, a single enforced startup application is the dominant source of the CPU spike rather than a combination of competing processes. The onset of symptoms aligns directly with the timing of a corporate startup application policy push.\n\nAffected users span multiple office locations and groups such as Sales and Mobile Workforce. The issue has been observed following policy pushes on consecutive days, indicating that successive rounds of startup policy revisions can independently trigger the same resource-contention behavior on newly targeted devices. In at least one case, the issue initially appeared attributable to a different root cause before diagnostics confirmed the startup policy as the actual trigger.", "cause": "A recently applied corporate startup policy introduced or re-enabled multiple resource-heavy startup items and service activity at user logon. The simultaneous launch of these processes caused sustained CPU and memory contention, delaying application launches and degrading post-login responsiveness on affected endpoints.", "variations": "- In some cases, a specific enforced startup application (such as an asset inventory agent) is the dominant source of the CPU spike, rather than a combination of multiple competing processes.\n- One affected user reported that performance partially self-recovered after several minutes, though applications remained slower than normal throughout the session.\n- The problematic startup policy was delivered via Group Policy (GPO) in some instances and via Intune endpoint management in others, but the resulting symptoms were identical.\n- At least one case initially appeared to have a different root cause (e.g., low disk space) before diagnostics confirmed the startup policy as the actual trigger.", "reporting": "Resolved by IT after identifying and adjusting the recently deployed startup application policy responsible for post-login resource contention on affected endpoints."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:53:14.423521+00:00", "final_grade": "Accepted"}' WHERE family = 'LPD' AND root_cause_id = 'LPD/resource-heavy-startup-policy';
UPDATE wiki_pages SET curated_description = '{"title": "Intermittent Post-Login Slowdown With High Antimalware CPU Usage", "symptoms": "The affected user reports intermittent, significant slowness on a corporate Windows 10 laptop immediately after sign-in. When the issue occurs, core productivity applications — including Outlook, a web browser, and File Explorer — take approximately 20–30 seconds each to become responsive, delaying the start of normal work activities such as accessing email and CRM tools. The slowdown is not consistently reproducible and appears to occur most frequently in the morning after the device has been powered off overnight, particularly when the user is working from a specific office location.\n\nDuring an occurrence, the Windows Defender antimalware service executable (MsMpEng.exe) is observed consuming approximately 95% of CPU resources in Task Manager while applications are slow to open. The user notes that the behavior persists even after previously disabling some startup applications, suggesting the slowdown is not attributable to user-configured startup items alone.\n\nThe intermittent nature of the issue prevented full reproduction during a live support session, and available evidence was insufficient to conclusively confirm the underlying trigger.", "cause": "The affected user experienced intermittent post-login endpoint slowdown that was not reproducible during diagnostic sessions. Transient startup or security scanning activity was suspected, but no confirmed root cause was established.", "variations": "", "reporting": "Intermittent post-login slowdown with high antimalware CPU usage was investigated but could not be conclusively attributed to a confirmed root cause; resolved by IT through monitoring and prior troubleshooting steps."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:54:04.922915+00:00", "final_grade": "Accepted"}' WHERE family = 'LPD' AND root_cause_id = 'LPD/unconfirmed-transient-post-login-slowdown';
UPDATE wiki_pages SET curated_description = '{"title": "Exchange Online Mailbox Throttling Disrupting Client Synchronization", "symptoms": "Affected users experience a sudden loss of email synchronization across Outlook desktop and Outlook mobile clients connected to their Exchange Online mailboxes. Desktop clients display a \"Disconnected\" status in the status bar, while mobile clients report sync errors or show a \"last synced: never\" indication. Outlook on the Web (OWA) typically continues to display incoming messages normally, confirming that the mailbox remains available at the service level even as thick clients fail to sync. The disruption often begins in the morning hours and persists through standard troubleshooting steps such as app restarts, device reboots, and toggling airplane mode.\n\nExchange Online diagnostics consistently reveal HTTP 429 throttling responses or EWS throttling entries against the affected mailboxes during sync attempts. Error code 0x800CCC0E has been observed during mobile sync failures alongside the throttling indicators. Rebuilding the Outlook desktop profile may restore mail flow on the desktop side, suggesting stale local profile or OST involvement, but the mobile client typically continues to fail even after the desktop recovers. Clearing and re-pairing the mobile ActiveSync partnership produces only brief or partial reconnection before sync breaks down again.\n\nCases in this category were escalated to Exchange Online backend support for throttle policy review and, where applicable, to MDM administrators after device non-compliance states were identified against affected mobile device partnerships.", "cause": "Exchange Online backend throttling was the primary cause, generating intermittent HTTP 429 responses and EWS throttling entries that interrupted ActiveSync and Outlook mobile connections. A stale or corrupted Outlook desktop profile and local OST file contributed to desktop-side disconnection, creating conflicting evidence, but were not the root cause of the persistent mobile sync failure. Recovery was achieved after a temporary throttle exception was applied at the service level.", "variations": "- Desktop Outlook intermittently toggling between Connected and Disconnected states rather than remaining fully disconnected\n- Split-client experience in which a desktop profile rebuild restores desktop sync while the mobile client remains in a failed state\n- MDM reporting a brief device non-compliance hold on the mobile device partnership, compounding the sync failure\n- Transient recovery of both desktop and mobile clients after ActiveSync re-pairing, followed by relapse into sync failure\n- Error code 0x800CCC0E observed during mobile sync failures concurrent with HTTP 429 throttling responses", "reporting": "Resolved by IT after Exchange Online backend support applied a temporary throttle exception and the desktop Outlook profile and mobile device partnership were reset."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:55:10.651190+00:00", "final_grade": "Accepted"}' WHERE family = 'OES' AND root_cause_id = 'OES/exchange-online-mailbox-throttling';
UPDATE wiki_pages SET curated_description = '{"title": "Corrupted Microsoft 365 Authentication Tokens Blocking Outlook Sync", "symptoms": "Affected users experience inconsistent email synchronization in Outlook Desktop on Windows 10, where the mailbox does not fully disconnect but messages fail to update reliably. The issue typically follows repeated sign-in prompts and recent account changes. Outlook may display a \"Disconnected\" status intermittently, and messages stop arriving despite the client maintaining partial connectivity to Exchange Online.\n\nThe sync failure extends beyond the desktop client, also affecting mobile mail access on managed iOS devices. The mobile application reports a \"sync failed\" error message. In some cases, affected users are initially uncertain whether mobile mail is impacted until both platforms are individually confirmed as failing. Messages may stop arriving approximately two days before the issue is reported.\n\nDiagnostic investigation reveals that the mailbox can reach Exchange Online and that mobile device partnership health appears normal. Rebuilding the Outlook profile does not resolve the issue, distinguishing it from a stale-profile scenario. The persistence of authentication prompts and sync failures across multiple platforms indicates an underlying account authentication token problem preventing Outlook from maintaining a valid mailbox session.", "cause": "Corrupted or invalid stored Microsoft 365 authentication tokens caused Outlook to repeatedly fail reauthentication. This prevented stable mailbox synchronization despite a healthy profile and compliant mobile partnership. The issue affected both desktop and mobile platforms simultaneously.", "variations": "- Outlook Desktop displayed a \"Disconnected\" status with intermittent connectivity rather than a complete and sustained connection loss.\n- The mobile mail client presented an explicit \"sync failed\" error message rather than silently failing to update.\n- Repeated authentication prompts preceded the sustained sync failure on the desktop client.\n- Profile rebuild on the desktop did not resolve the issue, distinguishing the behavior from a stale-profile scenario.", "reporting": "Resolved by IT by clearing cached credentials from Windows Credential Manager and forcing a fresh Modern Authentication sign-in, restoring service on both desktop and mobile."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T18:56:32.159735+00:00", "final_grade": "Accepted"}' WHERE family = 'OES' AND root_cause_id = 'OES/expired-m365-auth-tokens';
UPDATE wiki_pages SET curated_description = '{"title": "Intune Device Compliance Block Disrupts Exchange Online Mobile Sync", "symptoms": "Affected users experience a loss of email synchronization on managed mobile devices (iOS and Android) running Outlook Mobile, which typically displays a \"Disconnected\" banner, \"Last synced: never,\" or simply stops delivering new messages and push notifications. The disruption often begins abruptly — correlating with the device being marked non-compliant in Intune MDM — while mailbox access through Outlook on the web and, in most cases, the desktop Outlook client continues to function normally, confirming the underlying mailbox remains healthy.\n\nThe non-compliant state is triggered by factors such as a recent compliance policy update, a deprecated policy reference, a missing OS security patch, or an incomplete Company Portal compliance prompt. Exchange Online responds by blocking ActiveSync and EWS connectivity for the affected endpoints, with transport logs showing HTTP 403 rejections and, in some cases, HTTP 429 throttling caused by aggressive retry loops from stale Outlook sessions. The issue has been observed both for individual users and across groups of users enrolled under the same compliance policy, sometimes affecting multiple offices and device platforms simultaneously after a single policy push.\n\nDesktop Outlook clients are occasionally affected as well, showing intermittent disconnections or delayed mail delivery around the same timeframe. Desktop connectivity is typically restored independently after a profile rebuild or restart, pointing to a separable local profile issue rather than the same compliance block. The persistent and primary impact remains on the mobile device, where email access is fully blocked until device compliance is remediated and the mobile sync partnership is re-established.", "cause": "A change or update to Intune device compliance policies caused affected managed mobile devices to be evaluated as non-compliant, which triggered Exchange Online to block ActiveSync and mobile API access for those endpoints. In some cases, stale Outlook desktop profiles and transient EWS throttling from retry loops contributed secondary disruption but were not the persistent blocker.", "variations": "- Desktop Outlook continues to receive mail normally while only the mobile client is affected, indicating the compliance block is isolated to the mobile sync partnership.\n- Multiple users across more than one office or device group are affected simultaneously following a specific compliance policy rollout targeting an organizational unit.\n- Outlook Mobile displays a \"Connected\" status despite no new mail arriving and push notifications ceasing, masking the compliance block from the user''s perspective.\n- Exchange Online diagnostics reveal EWS HTTP 429 throttling on affected mailboxes caused by aggressive retry loops from stale Outlook profiles, compounding the compliance block.\n- The compliance block is triggered by a deprecated or outdated MDM policy reference rather than a newly introduced policy requirement.\n- The issue onset occurs overnight or in early morning hours, aligning with the compliance policy evaluation timestamp rather than any user action.\n- A device re-enrolled in MDM enters a brief non-compliant state during the re-enrollment process, triggering a surge of mobile sync requests and corresponding throttling.\n- An affected device is flagged non-compliant specifically due to a missing OS security patch, activating a conditional access policy blocking the mobile sync partnership until the patch is applied.", "reporting": "Resolved by IT after remediating Intune device compliance status and resetting the affected Exchange Online mobile sync partnerships."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T19:00:05.360799+00:00", "final_grade": "Accepted"}' WHERE family = 'OES' AND root_cause_id = 'OES/intune-mdm-device-compliance-block';
UPDATE wiki_pages SET curated_description = '{"title": "Stale or Corrupted Outlook Desktop Profile Blocks Exchange Online Sync", "symptoms": "Affected users running Outlook Desktop on Windows with Exchange Online mailboxes experience a persistent \"Disconnected\" state in the Outlook status bar, preventing the inbox and calendar from updating. Restarting Outlook, signing out and back in, or triggering manual Send/Receive does not resolve the condition. Outlook on the web continues to display current mail for the same mailbox, confirming that the Exchange Online service remains healthy and the failure is isolated to the local desktop client.\n\nIn many cases, mobile devices (primarily iOS) also stop syncing or display stale messages, indicating broken or outdated sync partnerships alongside the desktop profile corruption. Other applications on the affected workstations continue to function normally, and the Exchange Online service health dashboard shows no outage or degradation.\n\nThe issue has been observed as both isolated single-user incidents and multi-user events affecting teams within the same office. In one case, multiple members of a corporate sales team reported identical disconnected behavior on their laptops following a weekend patch cycle, with local OST inconsistencies identified across all affected machines. Triggering events include Office update or weekend patch cycles, profile update rollouts, and local profile restores. Autodiscover traces on affected workstations may reveal authentication failures (HTTP 401) tied to a stale profile GUID, and backend telemetry has occasionally shown intermittent HTTP 503 throttling during the incident window, complicating initial triage.", "cause": "Stale or corrupted Outlook desktop profiles—typically triggered by an Office update, weekend patch cycle, or profile update rollout—caused invalid cached mailbox settings, OST inconsistencies, and sync token mismatches that prevented the desktop client from establishing a healthy MAPI-over-HTTP session with Exchange Online. In several cases, stale mobile sync partnerships or device compliance conditions also required remediation before full mailbox synchronization resumed.", "variations": "- Manual Send/Receive and Autodiscover verification against the autodiscover endpoint did not restore connectivity on the desktop client.\n- Mobile sync remained delayed even after the desktop profile was successfully rebuilt, requiring a separate mobile sync partnership reset.\n- Backend Exchange Online telemetry showed intermittent HTTP 503 throttling during the incident window for one affected mailbox, complicating initial triage.\n- A group of users in the same office experienced simultaneous disconnected states after a weekend patch cycle, with OST file inconsistencies identified on each machine.\n- Some affected users experienced the issue on desktop only, with mobile email continuing to sync normally.\n- In certain cases, the mobile device was flagged as noncompliant in Intune, contributing to intermittent or blocked mobile email access alongside the desktop disconnection.\n- Autodiscover traces revealed authentication failures tied to a stale profile GUID in the local credential store rather than a broader connectivity or service issue.\n- Mobile sync failure presented as a silent lack of new mail rather than an explicit error message, in contrast to the desktop client''s visible \"Disconnected\" indicator.", "reporting": "Resolved by IT through Outlook desktop profile rebuild and, where applicable, mobile sync partnership reset and credential cache cleanup."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T19:03:36.994876+00:00", "final_grade": "Accepted"}' WHERE family = 'OES' AND root_cause_id = 'OES/stale-corrupted-outlook-desktop-profile-cache';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Mobile Sync Partnership Blocks Outlook Mobile Email", "symptoms": "Affected users experience a failure of Outlook mobile to synchronize their Exchange Online mailbox on managed iOS or Android devices. The Outlook mobile app displays a persistent or intermittent \"Disconnected\" status, and new messages stop appearing on the device. The mobile inbox appears frozen, showing only older messages, with the last-synced timestamp falling progressively behind. Restarting the app, force-closing it, or rebooting the device does not restore synchronization, and typically no explicit error code is presented to the user.\n\nThe issue is isolated to the mobile sync path. Other clients — desktop Outlook, Outlook on the web — continue to function normally for the same mailbox. Exchange Online service health dashboards show no active incidents, no mailbox throttling is present, and Intune device compliance checks return a compliant status with no pending policy violations. The combination of healthy webmail access, normal desktop connectivity, and compliant device status narrows the fault to the mobile sync relationship between the Outlook mobile app and Exchange Online.\n\nDiagnostic evidence in these cases includes stale last-sync timestamps on the Exchange Online mobile device partnership entries, HTTP 401 authentication errors in sync logs, and repeated failed sync sessions — all occurring despite the device reporting as compliant in Intune. In several cases the condition appears to have been triggered by a device-level change such as an iOS update, an Intune compliance policy transition, or a preceding desktop Outlook profile rebuild, after which the existing mobile partnership fails to re-establish properly.", "cause": "A stale Outlook mobile profile or invalid Exchange Online ActiveSync device partnership prevents the mobile client from maintaining a healthy sync session. The condition affects both iOS and Android platforms and is isolated to the mobile sync path rather than indicating a mailbox-wide Exchange Online outage. In observed cases the staleness was triggered by events such as an iOS update, an Intune compliance policy change, or a desktop profile rebuild, after which the existing mobile partnership failed to re-negotiate authentication successfully.", "variations": "- In one case, both the desktop Outlook client and the mobile client were affected simultaneously, with the desktop showing a disconnected state, repeated credential prompts, and send/receive failures due to an outdated cached profile alongside the stale mobile partnership.\n- Some users reported the issue began immediately after accepting an Intune device compliance update, suggesting the compliance transition disrupted the existing mobile sync partnership.\n- In at least one instance, the onset coincided with a major iOS version update, after which the mobile inbox ceased receiving new messages.\n- Exchange Online sync logs in one case showed repeated HTTP 401 authentication errors tied to the stale mobile partnership.\n- A minor Intune compliance refresh was required on one device alongside the partnership rebuild, though no active conditional access block was in effect.\n- A prior desktop Outlook profile rebuild was identified as a preceding event in one case, after which desktop sync recovered but mobile devices did not.\n- In one case, a user''s self-service account removal and re-add on the mobile client did not resolve the issue; server-side ActiveSync partnership clearance and profile rebuild were required. In a separate case, removing and re-adding the account on the mobile client alone resolved the issue without documented server-side partnership removal.\n- One incident involved both an iOS and an Android device simultaneously stuck in a disconnected state for the same mailbox, with both mobile partnership entries showing stale last-sync timestamps.", "reporting": "Resolved by IT clearing the stale Exchange Online mobile device partnership and rebuilding the Outlook mobile profile, after which synchronization resumed and current mail began flowing to the device."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T19:06:05.609138+00:00", "final_grade": "Accepted"}' WHERE family = 'OES' AND root_cause_id = 'OES/stale-mobile-sync-partnership';
UPDATE wiki_pages SET curated_description = '{"title": "Exchange Online Mailbox-Side Sync Fault Across Multiple Clients", "symptoms": "Affected users experience a failure of Outlook to sync new email and calendar data across multiple clients — both desktop and mobile — for the same Exchange Online mailbox. On mobile devices, the Outlook app shows stale data with no new messages arriving, while the desktop client displays a persistent or flickering Disconnected status. The issue is not limited to a single endpoint or platform; the same mailbox exhibits sync failure on both desktop and mobile simultaneously, distinguishing it from a client-side or device-specific problem.\n\nStandard local remediation steps do not resolve the issue. Rebuilding the Outlook profile on the desktop may temporarily restore connectivity on that client, but mobile sync remains broken. Toggling airplane mode, restarting the mobile app, and refreshing client sessions have no effect. MDM compliance checks on enrolled mobile devices return normal results, and no Microsoft 365 service outage is reported by the organization or visible to colleagues on the same network.\n\nThe failure is isolated to a single mailbox rather than a broader connectivity or tenant-level problem. Other users in the same office with different Exchange Online mailboxes are unaffected. Affected users are unable to rely on current mailbox data during the workday, impacting time-sensitive activities such as client-facing meetings.", "cause": "A suspected Exchange Online service-side mailbox synchronization fault or transient service condition is affecting multiple client sessions for a single user. There is insufficient local evidence to attribute the failure to the Outlook profile, device compliance, or network connectivity. The issue manifests at the mailbox level rather than at the client or tenant level.", "variations": "- In one case the desktop Outlook connection status flickered between Connected and Disconnected throughout the day rather than remaining steadily disconnected.\n- In one case a desktop profile rebuild restored desktop sync, but the mobile client continued to show Disconnected with no new mail, leaving the issue partially resolved on only one platform.\n- In one case the desktop client remained steadily Disconnected even after troubleshooting, with no partial restoration on any platform prior to escalation.", "reporting": "Resolved by IT; Exchange Online mailbox-level sync fault affecting multiple client platforms for a single user."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T19:07:05.308430+00:00", "final_grade": "Accepted"}' WHERE family = 'OES' AND root_cause_id = 'OES/suspected-server-side-mailbox-fault';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Outlook Profile and Unhealthy Mobile Sync Partnership Block Mailbox Access", "symptoms": "Affected users — primarily in Sales, Field Ops, and Corporate Sales organizational units — report that both Outlook desktop (Windows 10) and Outlook mobile (managed iPhones) simultaneously stop synchronizing mailbox content. The desktop client displays a \"Disconnected\" or intermittently cycling disconnection status in the status bar, while mobile devices cease receiving new mail entirely, with the account flagged as requiring attention. Last-sync timestamps remain stale, ranging from several hours to approximately 48 hours. Despite client-side failures, Outlook on the web (OWA) continues to display current messages for the same mailboxes, confirming that Exchange Online availability is not impacted.\n\nThe issue has been observed following scheduled Microsoft 365 tenant maintenance windows, with multiple users across different office locations affected in close succession. Exchange Online server-side telemetry may show intermittent successful sync activity for affected mailboxes, presenting a mixed-state condition rather than a complete outage. Microsoft 365 service health dashboards do not report a broader service disruption, and colleagues on the same team remain unaffected.\n\nOn the mobile side, managed devices enrolled via Intune may display a non-compliant status in the Company Portal app, and stale or unhealthy device partnerships are found registered against affected mailboxes in the Exchange Online administration console. In at least one instance, an outdated MDM legacy-block rule originally scoped for decommissioned older iOS endpoints was found incorrectly matching current devices post-maintenance. On the desktop side, the Outlook profile enters a corrupted or unhealthy state; creating a clean profile on the same workstation restores synchronization immediately.", "cause": "Mailbox sync failures were caused by a corrupted or stale Outlook desktop profile combined with an unhealthy mobile sync partnership and device compliance state on the mobile endpoint. An outdated MDM legacy-block rule in the sync policy, originally targeting decommissioned iOS devices, was found interfering with current device synchronization after a tenant maintenance window. These endpoint-side conditions disrupted Exchange Online reauthentication and synchronization while server-side mailbox availability remained healthy.", "variations": "- Some affected users report the issue beginning immediately on the first business day following a weekend maintenance window, while others experience onset mid-week with no obvious triggering event.\n- In certain cases, Intune explicitly reports the mobile device as non-compliant, whereas other affected users see no compliance warning in the Company Portal despite experiencing the same sync failure.\n- Exchange Online logs for some mailboxes show intermittent successful sync activity from the server side, presenting a mixed-state condition rather than a complete synchronization failure.\n- An outdated MDM legacy-block policy originally targeting decommissioned older iOS devices was found matching current iOS devices post-maintenance, contributing to mobile sync failures for compliant endpoints.\n- The duration of the sync outage varies, with some users experiencing stale mail for several hours and others reporting no client updates for up to approximately 48 hours before remediation.\n- Desktop Outlook showed intermittent disconnection cycling rather than a persistent disconnected state in some cases.\n- In one case, forcing a resync via Exchange Online PowerShell restored partial header updates on the desktop, but full folder synchronization required a complete profile rebuild.\n- One affected user had not recently changed their password or rebuilt their profile prior to the issue onset.", "reporting": "Resolved by IT through remediation of the stale Outlook desktop profile and reset of the mobile sync partnership and device compliance state."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T19:09:22.629621+00:00", "final_grade": "Accepted"}' WHERE family = 'OES' AND root_cause_id = 'OES/unresolved-endpoint-client-sync-state';
UPDATE wiki_pages SET curated_description = '{"title": "Corrupt Printer Driver Package Causes Queue Failures and Driver Unavailable Errors", "symptoms": "Affected users across multiple offices and departments experience print jobs that remain stuck in shared queues hosted on Windows print servers. Submitted jobs show zero percent progress or accumulate indefinitely without advancing, and the shared printers appear offline or display \"driver unavailable\" on client workstations. The issue affects all users mapped to the same server-hosted queue rather than individual machines, blocking routine and time-sensitive printing such as month-end reporting. Stuck job counts range from a handful to over one hundred entries across affected queues. Client-side actions — rebooting workstations, removing and re-adding printers, or clearing local queues — do not resolve the issue.\n\nOn the print server, the Print Spooler service logs repeated driver load failures, commonly Event ID 372, as well as codes such as 0x00000709, 2147500037, and ERROR_PRINTER_DRIVER_CORRUPT. Checksum or hash verification of the installed driver package against the approved repository copy confirms a mismatch or corruption, typically introduced by a recent automated deployment, scheduled driver update, or maintenance window. In severe cases the Print Spooler enters a crash loop, generating Event ID 7031 entries.\n\nRestarting the Print Spooler service provides only temporary relief. Jobs may briefly process after a restart but stall again within minutes as the spooler re-encounters the corrupt or mismatched driver package. The issue persists until the corrupted driver package is fully removed from the server''s driver store, replaced with the approved version, and affected queue mappings are rebuilt. Local printing methods such as USB-attached printers remain unaffected, confirming the fault is isolated to the server-side driver layer.", "cause": "A corrupt, incomplete, or checksum-mismatched printer driver package on the print server prevents the Windows Print Spooler from loading the driver assigned to shared queues. The corruption is typically introduced during an automated or scheduled driver deployment, leaving the server''s driver store in an invalid state that causes recurring driver load failures and blocks all job processing through the affected queues.", "variations": "- Some users observe jobs stuck in a \"printing\" state indefinitely rather than remaining at zero percent in a \"spooling\" state, or see printers grayed out in the printer list rather than explicitly offline.\n- The Print Spooler service may enter a crash loop (Event ID 7031) rather than remaining running in a degraded state.\n- Queue mappings may reference an older or incorrect driver version that no longer matches the package staged on the server, compounding the unavailable-driver condition.\n- Corruption may result from a partially written driver update leaving a mix of old and new files, an unsigned or improperly signed package, or a Windows cumulative update applied to the print server.\n- In some cases a single queue is affected while others on the same server continue functioning; in others, multiple queues sharing the same driver package fail simultaneously across departments.\n- A prior driver reinstall attempt or queue remap may provide only brief relief before the same failures recur, indicating incomplete earlier remediation.\n- Server-side inspection may reveal specific driver DLL files entirely absent from the expected spool driver directory, indicating an incomplete deployment rather than file-level corruption.\n- In one instance the corrupt driver deployment was traced to a Group Policy Object responsible for driver distribution, requiring correction of the policy in addition to the server-side driver replacement.", "reporting": "Resolved by IT after removing the corrupted printer driver package from the print server, reinstalling the approved driver version, and rebuilding the affected queue mappings."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:43:14.646144+00:00", "final_grade": "Accepted"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/corrupt-driver-package-spooler-load-failure';
UPDATE wiki_pages SET curated_description = '{"title": "Shared Print Queues Left Paused After Maintenance Window", "symptoms": "Multiple users at an office location reported that printing to shared queues hosted on a print server stopped working following recent maintenance changes. Submitted print jobs remained indefinitely in a spooling state and could not complete, affecting normal office printing workflows. The issue impacted more than one department-specific queue on the same server, with users in multiple departments confirming identical behavior.\n\nBecause the queues appeared superficially unhealthy rather than explicitly paused, initial troubleshooting explored other possibilities such as driver or spooler problems before the paused state was confirmed.", "cause": "During a maintenance window, an administrative action performed under a service account left the shared print queues in a paused state on the print server. The paused state blocked all queued jobs from advancing through the pipeline, though the queues did not display an obvious paused indicator, which delayed identification of the condition.", "variations": "- Some affected users encountered a \"Driver unavailable\" message on the shared queues, which initially suggested a driver-related fault but was ultimately a secondary symptom of the paused queue state.\n- Restarting the print spooler service provided brief, temporary relief before the issue recurred.", "reporting": "Resolved by IT after confirming and resuming the paused print queues on the print server."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:44:43.924114+00:00", "final_grade": "Accepted"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/queue-left-paused';
UPDATE wiki_pages SET curated_description = '{"title": "Print Spooler Fails Due to Incorrect Queue or Spool Directory Permissions", "symptoms": "Office users at a branch location reported that printing to a shared HP LaserJet hosted on the print server was failing. The printer remained visible in the shared queue and accepted job submissions, but jobs entered the queue without completing. Some users received access-related printing errors, while others observed the printer showing offline or encountered driver-unavailable and spooler-timeout messages. The issue was confirmed across multiple users on different floors of the building.\n\nDiagnostics ruled out a paused queue and an outdated or corrupt driver package. A test job submitted through the server-hosted queue failed during spooler processing and presented as an access error (EventID 7011), pointing to a permissions issue affecting the print queue or spool path rather than a driver fault. The failure was limited to processing on the print server side; affected workstations could see the printer and submit jobs, indicating workstation-level connectivity was intact.\n\nThe issue was resolved by restoring baseline ACLs for the print spooler service account, after which normal printing resumed for all affected users.", "cause": "Incorrect permissions on the affected shared printer queue or the associated spool directory on the print server prevented the Print Spooler service from processing submitted jobs. The spooler service account lacked the necessary ACLs to complete job rendering and output.", "variations": "- Some users reported the shared printer showing offline rather than receiving explicit access-related errors\n- Driver-unavailable or spooler-timeout messages appeared on certain workstations alongside the primary queue-stuck behavior\n- Users on multiple floors of the same building were affected, confirming the issue was not isolated to a single network segment", "reporting": "The issue was resolved by IT after restoring correct permissions on the print queue and spool directory for the spooler service account."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:46:07.090774+00:00", "final_grade": "Accepted"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/spool-directory-permissions';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Queue-to-Driver Mapping Causes Stuck Print Jobs", "symptoms": "Affected users across multiple departments experience print jobs that remain indefinitely stuck in shared print queues hosted on centralized print servers. Client workstations display \"Driver unavailable\" or \"printer offline\" status for the affected queue, and neither retrying the print job nor rebooting the workstation resolves the problem. The issue typically impacts all users submitting jobs to the same shared queue, with reported backlogs ranging from approximately 14 to over 30 stuck jobs across multiple users at a time.\n\nServer-side investigation consistently reveals that the shared print queue is still mapped to an outdated, incomplete, or corrupt driver package rather than the current approved driver version. In several cases the stale mapping originated from a prior driver reinstall or scheduled update that left the queue pointing to a legacy or partially installed driver entry. Print Spooler service logs on the affected print servers show repeated \"driver unavailable\" errors, driver load failures with CRC or checksum validation errors, and spooler crash events confirming that the resident driver package is corrupt or inconsistent.\n\nIn at least one instance, a spooler restart and queue clear on the print server provided only temporary relief, with jobs returning to a stuck-at-0% state and the printer reverting to offline within approximately 24 hours. The recurrence rendered restart-based workarounds ineffective as a lasting solution. Individual workstation troubleshooting has no effect because the driver mismatch or corruption exists on the print server''s queue-to-driver mapping. Incomplete remediation of the server-side driver and queue configuration has led to repeat occurrences after prior incidents were closed.", "cause": "A shared print queue on the affected print server remained mapped to an outdated, corrupt, or mismatched printer driver package—typically left behind after a partial driver reinstall or scheduled update. The stale queue-to-driver association caused the Windows Print Spooler to fail driver validation, reject driver loading, and leave submitted jobs stuck in the queue.", "variations": "- Windows Print Spooler Event ID 372 logged repeatedly on the print server, accompanied by spooler service errors following a prior driver reinstall\n- Queue mapped to a legacy driver variant (e.g., PCL5 instead of the approved PCL6 package) despite the correct driver being present in the central repository\n- Driver package corruption manifesting as CRC mismatch or checksum validation failures in server event logs, potentially caused during a scheduled update window\n- Spooler restart alone fails to resolve the issue when the underlying driver package is corrupt or the queue path references a stale server-side entry\n- Recurrence of the issue after a previous incident was closed, indicating incomplete remediation of the queue-to-driver association on the print server\n- Temporary relief after spooler restarts consistently degraded within approximately 24 hours, with the queue returning to its stuck or offline state\n- The issue was reproducible from multiple device types, including both workstations and laptops connecting to the same shared queue", "reporting": "Resolved by IT by reinstalling the approved printer driver package and correcting the queue-to-driver mapping on the print server."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:47:50.106118+00:00", "final_grade": "Accepted"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/stale-queue-driver-mapping';
UPDATE wiki_pages SET curated_description = '{"title": "Intermittent Print Job Stalling on Complex Documents", "symptoms": "Affected users across multiple departments reported that documents sent to a shared multifunction printer via the print server remained stuck in the queue, failing to print reliably. Print jobs stalled at zero percent progress for extended periods, and submitted jobs either hung indefinitely or experienced significant delays. The printer queue on the print server remained available, and multiple users confirmed the same behavior from different workstations mapped to the same shared printer.\n\nOn the print server, queued jobs displayed a \"Driver unavailable\" status, while affected users saw the printer appearing offline from their workstations. Standard queue and driver diagnostics did not reveal a consistent driver failure on the server side, and the spooler behavior was only partially reproducible during troubleshooting.\n\nA simple test page submitted from one workstation processed successfully, indicating that the queue itself was functional. However, larger or more complex jobs — including a multi-page PDF — failed repeatedly on retries. This pattern pointed to an intermittent rendering or printer-side processing issue that could not be fully isolated through standard diagnostics alone.", "cause": "Intermittent print job processing failures occurred that were not explained by queue state or driver version. The issue appeared related to specific document rendering or downstream printer handling. The root cause could not be fully isolated through standard diagnostics and required further vendor or platform escalation.", "variations": "- Some users reported only an \"offline\" printer status on their workstations rather than the \"Driver unavailable\" message seen on the server side.\n- The issue was observed across at least three floors, suggesting it was not isolated to a single network segment or department.\n- Small or simple print jobs (e.g., a single test page) completed successfully, while larger multi-page documents consistently stalled.", "reporting": "Intermittent print job stalling on complex documents escalated for further vendor or platform investigation by IT."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:48:40.322118+00:00", "final_grade": "Accepted"}' WHERE family = 'PDQ' AND root_cause_id = 'PDQ/unresolved-rendering-escalation-holding';
UPDATE wiki_pages SET curated_description = '{"title": "Broken NTFS Inheritance or Explicit Deny ACE on Shared Folder", "symptoms": "Affected users attempting to open a Finance department shared drive from Windows 10 workstations encounter a credential prompt followed by an \"Access is denied\" error (in some cases error code 0x80070005). The issue prevents users from listing or opening files within the Finance folder path, despite their Active Directory accounts holding confirmed membership in the appropriate file-access security groups. The problem persists after standard client-side remediation steps such as signing out and back in, clearing cached SMB credentials, disconnecting and remapping the network drive, and even attempting access from a different workstation — indicating a server-side rather than client-side cause.\n\nInvestigation consistently reveals that the affected users'' AD group memberships and directory replication are correct across all domain controllers. However, NTFS ACL review on the file server discloses broken permission inheritance on the Finance folder or an explicit deny access control entry (ACE) on a parent or target folder that overrides the group-based allow permissions. In at least one case, the deny ACE was traced to a bulk permission change that inadvertently applied an explicit deny entry for a Finance security group. File server access logs corroborate the denial, recording NT_STATUS_ACCESS_DENIED events for the affected users'' security identifiers even after group membership updates are confirmed.\n\nColleagues on the same Finance team who belong to a legacy or alternate security group that is separately listed on the folder ACL are unaffected, which initially makes the issue appear account-specific. No client-side changes alone restore access; the issue is resolved only after server-side ACL corrections are applied.", "cause": "NTFS permissions on the Finance department shared folder were misconfigured. The expected security group was either absent from the folder ACL due to broken or removed permission inheritance, or an explicit deny ACE on a parent or target folder overrode the allow permissions granted through the group. Affected users held valid AD group membership, but the file server''s effective permissions denied access because of the conflicting ACL configuration. In one case, a folder/share ACL inheritance mismatch continued to deny the user''s SID even after correct group membership was confirmed and applied.", "variations": "- In some cases the mapped drive reconnects successfully at the share level, but the \"Access is denied\" error appears only when navigating into a specific department subfolder beneath the Finance share.\n- File server logs in certain instances record intermittent rather than consistent NTFS permission errors, with access occasionally succeeding briefly after a token refresh before failing again on subsequent attempts.\n- At least one case involved a colleague''s access functioning normally because the colleague''s account belonged to a legacy security group that remained on the folder ACL, while the current standard group was missing from the ACL entirely.\n- In one instance, initial access restoration steps (credential cleanup and drive remap) appeared to resolve the issue in a remote test session, but file server logs continued to record deny events, revealing a deeper ACL inconsistency.", "reporting": "Resolved by IT through server-side NTFS ACL remediation, removing the erroneous explicit deny ACE and restoring proper permission inheritance on the affected folder hierarchy."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:49:49.299707+00:00", "final_grade": "Accepted"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/broken-ntfs-acl-inheritance-or-deny-ace';
UPDATE wiki_pages SET curated_description = '{"title": "Missing AD Security Group Membership Denies Department Share Access", "symptoms": "Affected users report being unable to open departmental shared drives (most commonly Finance, but also HR, Engineering, and other department folders) from mapped drive letters or direct UNC paths on domain-joined Windows workstations. Access attempts prompt for credentials and then return an \"Access is denied\" error (0x80070005 / NT_STATUS_ACCESS_DENIED). In some cases the credential prompt loops repeatedly before ultimately failing. Other network shares not gated by the same security group remain accessible, and colleagues in the same department and office can open the identical share without difficulty, confirming the issue is account-specific rather than a file server or network outage.\n\nStandard self-remediation steps — signing out and back in, clearing cached credentials via Credential Manager, and remapping the drive — do not resolve the issue. This persistence distinguishes the problem from stale-credential scenarios and points to a server-side entitlement gap. In at least one case the mapped drive shows a \"Disconnected\" status, and in another the file server audit log contains explicit NTFS access-denied entries for the affected user''s SID.\n\nInvestigation in every instance reveals that the affected user''s Active Directory account is missing membership in the department-level security group referenced by the share and NTFS ACLs. The absence stems from varied circumstances: incomplete onboarding or inter-department transfer provisioning, automated AD group synchronization or cleanup scripts that inadvertently removed the membership, or an access request that had not yet been fulfilled. Without the group SID in the user''s Kerberos token, the file server denies authorization regardless of valid credentials.", "cause": "The affected user''s Active Directory account was not a member of the security group required by the department shared drive''s share-level and NTFS access control lists. Because the group SID was absent from the user''s logon token, the file server denied authorization even though authentication succeeded. The missing membership resulted from provisioning gaps during onboarding or role transfers, automated AD group cleanup scripts, or unfulfilled access requests.", "variations": "- Missing group membership caused by an onboarding or inter-department transfer process that did not include the required shared-drive entitlement\n- Missing group membership triggered by a scheduled AD group audit or cleanup that inadvertently removed the user from a still-required group\n- Missing group membership caused by an automated nested-group cleanup script or AD synchronization event that dropped the share entitlement\n- Access request submitted through a self-service portal had not yet been provisioned into Active Directory\n- Affected user could browse to the top-level share path but was denied access only at a specific subfolder rather than at the share root\n- Credential prompt looped repeatedly before ultimately returning access denied, rather than presenting a single prompt followed by immediate denial\n- Affected user tested access from a colleague''s workstation and observed the same denial, confirming the issue followed the account\n- A separate broken-ACL-inheritance issue on subfolders was identified during investigation but was unrelated to the individual user''s missing group membership", "reporting": "Resolved by IT by adding the affected user''s account to the required Active Directory security group and refreshing the logon session to obtain an updated Kerberos token containing the correct group entitlement."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:54:53.023406+00:00", "final_grade": "Accepted"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/missing-ad-security-group-membership';
UPDATE wiki_pages SET curated_description = '{"title": "Compound Missing AD Group Membership and Stale Cached Credentials Block Share Access", "symptoms": "Affected users on domain-joined Windows 10 workstations report being unable to open departmental shared drives (most commonly Finance, but also Sales and Engineering) via mapped network drives or direct UNC paths. The mapped drive repeatedly prompts for credentials and then returns an \"Access is denied\" error (frequently surfaced as 0x80070005 or NT_STATUS_ACCESS_DENIED). The issue is isolated to specific user accounts — colleagues on the same team with valid group membership can access the same share without difficulty, confirming the problem is not a broader server or network outage.\n\nInvestigation consistently reveals a compound condition: the affected user''s Active Directory account is missing the required security group that governs access to the department share, and the workstation retains stale cached credentials or an outdated security token that has not been refreshed to reflect the current account state. The stale credential causes the repeated prompt cycle — the workstation presents outdated authentication material, the file server rejects it, and the user is re-prompted in a loop before ultimately receiving access denial. In some cases the user appears in a related distribution list but not in the security group actually referenced by the share ACL, creating a false impression of valid membership.\n\nContributing factors observed across tickets include broken NTFS permission inheritance or explicit deny entries on subfolders, legacy individual-SID ACL entries from prior migrations conflicting with the group-based model, stale Group Policy Object references affecting drive-mapping behavior, and delayed token evaluation on the file server following same-day AD group changes. The issue typically surfaces after a password reset, an AD group cleanup, or a weekend maintenance window.", "cause": "The affected user''s Active Directory account was missing the required security group membership granting access to the departmental shared drive, often due to an AD group cleanup, organizational restructure, or a newly requested addition that had not yet propagated. The condition was compounded by stale cached SMB credentials or an unrefreshed Kerberos token on the workstation, causing repeated credential prompts and continued access denial even when correct credentials were supplied. In several cases, broken NTFS permission inheritance or legacy per-user ACL entries on the share further contributed to the access failure.", "variations": "- Onset immediately following a corporate password reset, with stale Credential Manager entries retaining the old password on the mapped drive.\n- Missing group membership resulted from a newly submitted access request that had not yet propagated to the user''s logon token, rather than an inadvertent removal.\n- File server retained stale group evaluation from before a same-day AD membership update, delaying recognition of newly granted entitlements.\n- Broken NTFS permission inheritance or an explicit deny entry on a subfolder compounded the missing-group condition, blocking access even after group membership was corrected.\n- A legacy explicit allow entry tied to an individual user SID from a prior migration created conflicting ACL state alongside the expected group-based permissions.\n- A stale Group Policy Object reference (e.g., an outdated shared-drive mapping policy) contributed to drive-mapping misbehavior on the affected workstation.\n- Affected user''s account appeared in a departmental distribution list but not in the corresponding security group referenced by the share ACL, giving a false appearance of valid membership.\n- One affected user attempted self-remediation by deleting and remapping the drive via command-line tools without success; the issue persisted until the underlying entitlement and credential state were corrected.", "reporting": "Resolved by IT by restoring the correct Active Directory security group membership, clearing stale cached credentials, and refreshing the user''s security token and session context."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:58:06.664096+00:00", "final_grade": "Accepted"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/missing-group-plus-stale-credential-or-acl-compound';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Cached SMB Credentials Cause Mapped Drive Access Denial", "symptoms": "Affected users on domain-joined Windows 10 workstations experience repeated credential prompts followed by \"Access is denied\" messages when attempting to open department shared folders via mapped network drives in File Explorer. In one instance, the denial was accompanied by Error 5. The issue prevents normal access to SMB file shares and blocks routine file work.\n\nThe underlying cause is stale cached SMB credentials stored on the workstation. In the reported cases, the credential cache became outdated due to a recent change — either an AD group membership update that granted new share access, or a same-day password change. Although the user''s Active Directory membership and share permissions are confirmed correct and fully replicated across domain controllers, the workstation continues to present outdated cached credentials from Windows Credential Manager when connecting to the file server. This causes the SMB session to authenticate with obsolete information, resulting in denied access even when the user re-enters current, valid credentials at the prompt.", "cause": "The affected user''s workstation retained stale cached SMB credentials in Windows Credential Manager that did not reflect a recent change — either a password update or a newly granted AD group membership for the target share. Despite correct AD group membership and fully replicated permissions across domain controllers, the workstation continued to present outdated credentials during SMB authentication, causing repeated access denials. Historical NTFS deny entries were noted on the file server but were not the immediate cause, as access was restored without any ACL modification.", "variations": "- Error 5 explicitly returned alongside the \"Access Denied\" message (observed in one case involving a post-AD-group-change scenario)\n- Credential prompt and access denial reproduced when navigating directly to the UNC share path, in addition to the mapped drive (observed in one case involving a same-day password change)\n- Stale credentials triggered by an AD group membership change processed days prior, with full domain controller replication confirmed; resolution in that instance included refreshing the Kerberos ticket\n- Stale credentials triggered by a same-day password change on the affected user''s account\n- Historical NTFS deny entries noted on the file server for separate follow-up by the file server owner", "reporting": "Resolved by IT by clearing stale cached credentials and remapping the affected network drive with fresh authentication."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T14:59:11.709878+00:00", "final_grade": "Accepted"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/stale-cached-smb-credentials';
UPDATE wiki_pages SET curated_description = '{"title": "Mapped Drive Targeting Retired UNC Path After File Server Migration", "symptoms": "Affected users experience \"Access Denied\" errors (0x5) when attempting to open a shared network drive via a mapped drive letter. The same error may also occur when navigating directly to the correct current UNC path in Windows Explorer. All subfolders within the share are equally inaccessible, and the issue persists regardless of the access method used.\n\nIntermittent credential prompts appear during access attempts, but entering valid domain credentials does not resolve the error. Active Directory group membership for the affected user is verified as correct, and entitlement checks confirm the user should have access to the share.\n\nThe issue is isolated to the individual workstation; colleagues in the same department and security group retain normal access to the share, indicating the problem is specific to the affected user''s session or drive configuration rather than a broader permissions or server-side outage.", "cause": "The affected user''s mapped drive was pointing to a stale or retired Finance share path from a previous file server migration. The outdated UNC location produced Access Denied behavior despite valid group membership. Cached credentials associated with the retired path also prevented successful authentication when the user attempted to reach the correct server directly.", "variations": "- The mapped drive letter points to a retired UNC path from a previous file server migration, while the user believes it references the current server; the direct UNC path to the correct server also fails due to stale cached credentials associated with the outdated path.\n- Credential prompts appear intermittently rather than consistently, and supplying correct credentials each time still results in Access Denied.", "reporting": "The issue was resolved by IT after identifying and correcting a mapped drive that referenced a retired UNC path from a prior file server migration."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:00:07.369907+00:00", "final_grade": "Accepted"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/stale-or-wrong-mapped-share-path';
UPDATE wiki_pages SET curated_description = '{"title": "Kerberos Token Not Reflecting AD Group Despite Confirmed Membership", "symptoms": "Affected users experience \"Access is denied\" errors and repeated credential prompts when attempting to open a departmental shared drive. The issue occurs both through a mapped drive letter and via direct UNC path access to the same file server share. Entering credentials multiple times does not resolve the prompts, and the folder remains inaccessible. The issue is account-specific; colleagues on the same team with equivalent share access are able to open the folder without difficulty.\n\nDiagnostic review of the affected user''s Active Directory account confirms that the correct security group membership is present. However, the Kerberos token on the affected workstation does not consistently reflect that group membership. The UNC path and drive mapping were verified as correct, ruling out a stale or misconfigured shortcut. The inconsistency between confirmed AD group membership and the token presented during authentication points to a backend replication or authentication-layer issue that could not be isolated to a single cause during initial investigation.", "cause": "There is conflicting evidence between directory entitlement state and actual SMB authentication behavior. The affected user''s Active Directory group membership is confirmed as correct, but the Kerberos token presented during file share authentication does not consistently reflect that membership. The root cause is attributed to a backend permission replication or file service authentication issue requiring higher-tier review.", "variations": "", "reporting": "Resolved by IT through escalation for higher-tier review of a backend replication or authentication-layer inconsistency affecting SMB share access."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:00:58.607778+00:00", "final_grade": "Accepted"}' WHERE family = 'SDA' AND root_cause_id = 'SDA/unconfirmed-backend-replication-or-auth-escalated';
UPDATE wiki_pages SET curated_description = '{"title": "Endpoint Protection Application Control Blocking Software Center Installer", "symptoms": "Affected users on managed Windows 10 corporate endpoints experience application installation failures when attempting to deploy software through Software Center. The endpoint protection application control policy actively blocks the installer, producing error messages such as \"Installation blocked by policy,\" \"Installation blocked by Endpoint Protection,\" or policy-related error codes including INSTALL_BLOCKED_POLICY_CHECK (0x80070005), 0x87D00324, or EP-4031. Device enrollment, Intune compliance status, and entitlement group membership are confirmed as healthy in all cases — the block originates solely from the endpoint protection allowlist or approval policy.\n\nA common secondary symptom is that the requested application either does not appear in the Software Center catalog, disappears from the available applications list after a failed installation attempt, or is intermittently visible but consistently fails upon install initiation. Retrying the installation without a policy change produces the same denial. Endpoint protection logs on affected devices confirm a quarantine or deny action triggered by an application control rule against the installer package, intercepting it before Software Center can complete the deployment.\n\nThe issue has been observed across multiple offices, departments, and application types — including VPN clients, productivity suites, line-of-business tools, and finance applications. Multiple users within the same deployment group can be simultaneously affected when the installer approval entry is missing from the relevant endpoint protection policy. Local IT personnel attempting a manual push of the installer encounter the same block, confirming the issue is not limited to the self-service Software Center workflow.", "cause": "An endpoint protection application control policy blocked the application installer because the installer''s hash, publisher signature, or approval entry was not present in the approved-applications allowlist assigned to the affected devices. This prevented Software Center from completing or presenting the deployment despite valid entitlement and targeting.", "variations": "- In some cases the endpoint protection block message specifically cites an unapproved or unknown publisher signature as the reason for denial.\n- The application may briefly appear in Software Center before vanishing from the catalog after the initial blocked install attempt, rather than being absent from the start.\n- Multiple users within the same deployment group can be affected simultaneously when the installer approval entry is missing from the endpoint protection application control policy assigned to that group.\n- The block may reference a named policy (e.g., \"BlockUnsignedInstallers\" or a block-unknown-installers rule) rather than a generic policy-check failure code.\n- Local IT personnel attempting a manual push of the installer encounter the same policy block, confirming the issue is not limited to the self-service Software Center workflow.\n- In one case, endpoint protection logs specifically identified the installer hash value as the attribute triggering the deny action.\n- One affected user reported inconsistent Software Center behavior during troubleshooting, with the application intermittently appearing or not appearing in the catalog.", "reporting": "Resolved by the security team updating the endpoint protection allowlist to approve the blocked installer and refreshing policy on affected devices."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:02:53.169669+00:00", "final_grade": "Accepted"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/endpoint-protection-app-control-block';
UPDATE wiki_pages SET curated_description = '{"title": "Endpoint Protection Installer Block Combined With Stale Intune Inventory", "symptoms": "Affected users on corporate-managed Windows endpoints report that approved applications are either missing from the Software Center catalog or fail immediately upon installation with a security policy block. Error messages consistently reference Endpoint Protection or application control denial, with common indicators including \"Installation blocked by Endpoint Protection,\" \"blocked by security policy,\" or specific coded failures such as \"PolicyCheckFailed:EP-403,\" accompanied by error codes including 0x80070005, 0x80070490, 0x800704EC, 0x87D13B3, 0x87D00607, 0x87D1FDE8, or 0xD0000247. In some cases the application is visible but fails instantly upon launch; in others it is entirely absent from the catalog or appears intermittently across sessions.\n\nInvestigation consistently reveals two co-occurring conditions. First, Endpoint Protection or Defender Application Control policy is actively blocking the installer due to a hash mismatch, missing publisher signature approval, heuristic detection, or the installer not appearing on the security allowlist. Second, the device''s Intune inventory is stale—with last-sync timestamps ranging from 36 hours to approximately 30 days behind—preventing updated allowlist approvals, entitlement targeting, and application assignments from propagating to the endpoint. Neither condition alone fully accounts for the reported behavior.\n\nThe issue affects multiple departments, offices, and application titles rather than a single software package. In recurring instances, a prior inventory refresh temporarily restores visibility, but the issue returns because the Endpoint Protection effective policy on the device still lacks the necessary approval. In some cases, the application is visible under an administrative account but absent under the affected user''s standard account due to stale entitlement state. Multiple users within the same teams are typically affected concurrently.", "cause": "Endpoint Protection or Defender Application Control policy was blocking the approved application installer because the required publisher signature, hash, or allowlist approval had not propagated to the endpoint. Concurrently, the device''s Intune inventory and policy state were stale, preventing current entitlement targeting, application assignments, and updated security approvals from reaching the device. The combination of the active security block and outdated device policy caused both catalog visibility failures and installation denials in Software Center.", "variations": "- The application is completely absent from the Software Center catalog, with no error shown until the user attempts to run the installer manually.\n- The application is visible in Software Center but fails immediately upon clicking Install, without ever beginning the installation process.\n- The Endpoint Protection block references a specific policy name or coded failure rather than a generic \"blocked by policy\" message.\n- The block is triggered by a publisher signature or certificate mismatch, or by heuristic behavioral detection, rather than an unapproved installer hash.\n- The issue recurs after a previous resolution due to a new installer version introducing an updated hash not yet added to the allowlist.\n- The application appears intermittently or is visible under an administrative account but absent under the affected user''s standard account.\n- Multiple users within the same office or device group experience the issue simultaneously, indicating a broader policy or sync gap affecting a collection of devices.\n- A recently re-enrolled or hardware-replaced device did not trigger a full Intune inventory sync, resulting in stale inventory despite the recent enrollment date.", "reporting": "Resolved by IT by updating the Endpoint Protection allowlist to approve the installer and forcing an Intune device inventory sync and policy refresh on the affected endpoint."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:07:26.052829+00:00", "final_grade": "Accepted"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/endpoint-protection-block-plus-stale-inventory';
UPDATE wiki_pages SET curated_description = '{"title": "FinanceApp Unavailable in Software Center Despite Valid Entitlement", "symptoms": "Affected users on managed corporate Windows devices reported that FinanceApp v4.2.1 could not be installed from Software Center. The application was either entirely absent from the Software Center catalog or unavailable for installation, despite the users being confirmed or expected members of the appropriate entitlement groups. Standard self-service remediation steps — including manual machine policy retrieval cycles, Software Center restarts, sign-out/sign-in attempts, and full device reboots — did not resolve the issue.\n\nWhen affected users attempted alternative installation methods, such as running the approved installer package directly or accessing a forwarded available-deployments link, the installations were blocked. Users received authorization or entitlement error messages indicating they were not permitted to install the application. In some instances, users encountered an additional security policy block when attempting manual installation from an internal portal. The issue directly impacted finance workflows, as the affected users required FinanceApp to complete time-sensitive quarter-end reporting and reconciliation tasks.\n\nIn both cases, the devices were enrolled in the organization''s management platform and connected to the corporate network at the time of the reports. Diagnostic data was limited on one device due to a degraded management client state, which constrained the ability to isolate a confirmed root cause.", "cause": "FinanceApp deployment targeting was misconfigured or not being processed correctly in the endpoint management platform, preventing correct policy evaluation against the device scope despite valid entitlement group membership. A confirmed root cause could not be fully determined because device management and security telemetry were incomplete during diagnostics.", "variations": "- In one case, the application was absent from the catalog due to a backend deployment targeting misconfiguration in the management platform, which prevented correct policy evaluation against the device scope despite valid entitlement group membership.\n- In another case, the user additionally encountered an explicit Endpoint Protection security block (referencing a policy rule for unapproved installations) when attempting to run the installer manually from an internal portal.\n- One affected device exhibited a degraded management client state, with stale policy and protection agent reporting dates, which prevented diagnostic tools from returning sufficient telemetry to isolate the root cause.", "reporting": "Resolved by IT; FinanceApp deployment targeting misconfiguration with incomplete diagnostic telemetry."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:09:26.061071+00:00", "final_grade": "Accepted"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/indeterminate-incomplete-telemetry';
UPDATE wiki_pages SET curated_description = '{"title": "Missing Entitlement Group Membership Blocks Application Install", "symptoms": "Affected users report that a required business application is missing from the Software Center or Company Portal catalog and cannot be installed through normal self-service deployment. When installation is attempted—via a direct link, alternate install path, or after a manual catalog refresh—the request is blocked with an entitlement or policy error. Observed messages include \"Entitlement check failed: user/device not authorized,\" \"Not available for this user,\" \"Installation blocked by policy,\" and \"Installation blocked: entitlement check failed.\" Associated error codes and statuses seen in client logs or on-screen include 0x87D00231, 0x80180014, 0x87D00607, 0x87D1061E, 0xE000020B, and POLICY_CHECK_FAILED.\n\nIn some cases the application is entirely absent from the catalog with no error shown until a direct install is attempted. In others, the application appears after a Software Center refresh but still fails on installation. The block may surface in both Software Center and Company Portal simultaneously in co-managed environments.\n\nInvestigation consistently confirms that the affected device is properly enrolled and compliant in Intune, with no endpoint protection or security blocks present. The root cause is that the affected user''s account is not a member of the required application entitlement security group in Entra ID or Active Directory. Without this membership, the Intune deployment is neither offered nor permitted by policy evaluation. Standard client-side troubleshooting—restarting Software Center, signing out, or forcing a policy sync—does not resolve the issue, as the gap exists at the directory level. In some instances, a stale Intune policy sync state on the device further delays catalog visibility.", "cause": "The affected user''s account was not a member of the required entitlement security group in Entra ID or Active Directory used for Intune application assignment targeting. Because the deployment group membership was missing, policy evaluation did not authorize or present the application, and Software Center blocked the installation.", "variations": "- The application is entirely absent from the catalog with no error shown until a direct install path is attempted.\n- The application appears in Software Center only after a manual refresh but still fails with a policy or entitlement error on install attempt.\n- The block appears in both Software Center and Company Portal simultaneously in co-managed ConfigMgr/Intune environments.\n- Client-side logs surface a POLICY_CHECK_FAILED status rather than a numeric error code.\n- Error code 0x87D1061E (\"Installation blocked by policy\") returned during the install attempt.\n- Error code 0xE000020B (\"Installation blocked: entitlement check failed\") returned during the install attempt.\n- Different numeric error codes (0x87D00231, 0x80180014, 0x87D00607) are returned depending on the application and deployment configuration, but all trace to the same missing group membership.\n- Stale Intune device sync contributing to delayed or missing application catalog visibility.", "reporting": "Resolved by IT by adding the affected user to the required entitlement security group and triggering a policy refresh; missing entitlement group membership blocking application deployment."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:12:14.930510+00:00", "final_grade": "Accepted"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/missing-entitlement-group-membership';
UPDATE wiki_pages SET curated_description = '{"title": "Missing Entitlement Group Membership With Endpoint Protection Blocking", "symptoms": "Affected users on corporate-managed Windows endpoints attempt to install a required application through Software Center but encounter installation failures. The application either does not appear in the Software Center catalog at all or is visible but immediately blocked when installation is attempted. Common error messages include \"user not entitled\" (error 0x80180014), \"policy check failed\" (errors 0x87D00231 and 0x80070490), and \"entitlement not found.\" Standard self-remediation steps such as restarting the device, restarting Software Center, clearing the SCCM cache, and forcing an Intune sync do not resolve the issue. Colleagues in the same team or role have the application available and can install it without difficulty.\n\nInvestigation consistently reveals that the affected user''s Active Directory account is missing from the security group used to target the application deployment. Because group membership is the criterion for Intune or SCCM policy targeting, the application is either not offered to the device or fails policy evaluation during installation.\n\nIn most cases, a compounding factor is also identified: Endpoint Protection on the device actively blocks or quarantines the application installer due to application control policy. This manifests as quarantine notifications from the endpoint protection agent, installer hash denials, or policy check failures that prevent the installer from launching. The endpoint protection block is frequently discovered as a secondary condition that must also be addressed before installation can succeed. In some instances, however, the missing group membership alone accounts for the failure, and endpoint protection approval is noted only as a precautionary verification step.", "cause": "The affected user''s Active Directory account was not a member of the required application entitlement security group, so the deployment was not targeted correctly and the application remained unavailable or failed policy evaluation. Concurrently, Endpoint Protection application control policy blocked or quarantined the installer, requiring separate security approval and policy refresh before installation could proceed.", "variations": "- The application is completely absent from the Software Center catalog rather than visible but blocked, with Intune showing the device is not targeted for the app.\n- Endpoint Protection quarantines the installer on execution, producing a visible security notification on the device in addition to the policy check failure.\n- The installer is denied before it ever launches, with Software Center displaying \"Installation blocked by Endpoint Protection\" and no installer window appearing.\n- The application is visible in Software Center but absent from Intune app approvals under the user''s account, indicating a gap between deployment visibility and entitlement targeting.\n- A direct installation attempt from a network share fails with a PolicyCheckFailed error, bypassing Software Center but encountering the same underlying policy restriction.", "reporting": "Resolved by IT by adding the affected user to the required entitlement security group and ensuring Endpoint Protection approval and policy synchronization were completed."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:13:26.401889+00:00", "final_grade": "Accepted"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/missing-entitlement-group-membership-plus-endpoint-protection-block';
UPDATE wiki_pages SET curated_description = '{"title": "Missing Entitlement, Stale Inventory, and Endpoint Protection Block Combined", "symptoms": "Affected users on managed Windows 10 Enterprise devices report that required applications are unavailable or blocked in Software Center. The target application either does not appear in the Software Center interface, appears intermittently, or is listed with a persistent \"Blocked\" status. When installation is attempted, users receive messages such as \"blocked by policy,\" \"blocked by Endpoint Protection,\" or \"installation blocked by policy check,\" and in some cases error codes such as 0x80070490 or 0x87D1041C are returned. No download or installation proceeds, and the issue persists across Software Center restarts and device reboots.\n\nInvestigation consistently reveals three co-occurring factors on affected devices. First, the user''s account is missing membership in the required Intune entitlement or deployment group, meaning the application is not correctly targeted. Second, the device''s Intune inventory and policy state is stale — with the last successful check-in ranging from 48 hours to 14 days prior — preventing updated assignments from reaching the endpoint. Third, Endpoint Protection application control is actively quarantining or blocking the installer.\n\nCorrecting any single factor in isolation does not resolve the issue. In some cases, an entitlement group correction or an Intune inventory refresh temporarily restores application visibility, but the blocked state returns after a reboot because the remaining conditions have not been addressed. Resolution requires remediation of all three factors before the application becomes available and installable through Software Center.", "cause": "Application deployment was blocked by a combination of missing Intune entitlement group membership, stale device inventory preventing current policy targeting from propagating to Software Center, and Endpoint Protection application control quarantining the installer. All three conditions had to be present simultaneously for the issue to manifest, and correcting only one or two factors was insufficient to restore normal application availability.", "variations": "- In some instances, the application appears listed in Software Center but is marked with a persistent \"Blocked\" status and no download initiates, rather than being entirely absent from the interface.\n- One affected user received error code 0x80070490 when attempting to run the installer directly from a network deployment share rather than through Software Center.\n- One user reported error code 0x87D1041C accompanying the policy block during each installation attempt, including after an Intune inventory refresh and policy re-push.\n- In at least one case, an initial entitlement group correction was made but did not take effect on the endpoint, leading the user to reopen the ticket after rebooting and retrying without success.\n- In one case the application briefly became available after an Intune refresh but reverted to a blocked state following a device reboot, demonstrating incomplete synchronization of entitlement and assignment data.\n- One user reported the Endpoint Protection component specifically flagged the application installer file during execution, contributing to the installation failure alongside the missing entitlement.\n- The particular application blocked varies across tickets — including line-of-business applications, marketing tools, and VPN clients — but the underlying combination of missing entitlement, stale inventory, and endpoint protection block is consistent.\n- Some affected devices are located at different regional offices, and the application visibility issue may affect multiple devices assigned to the same site when entitlement and inventory conditions overlap.", "reporting": "Resolved by IT by correcting entitlement group membership, forcing a device inventory synchronization and policy refresh, and clearing the Endpoint Protection application control block."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:15:26.208626+00:00", "final_grade": "Accepted"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/missing-entitlement-plus-endpoint-protection-and-stale-inventory';
UPDATE wiki_pages SET curated_description = '{"title": "Missing Entitlement Group Membership Combined With Stale Device Inventory", "symptoms": "Affected users on corporate-managed Windows endpoints attempt to install a required application from Software Center but find it either missing from the catalog entirely or listed with the Install button greyed out. When the application is visible and installation is attempted, an entitlement policy failure is returned — reported variously as \"EntitlementCheckFailed,\" an entitlement-related error code, or an \"installation blocked\" message referencing an entitlement check against the user''s account. The application may also be absent from Company Portal with no actionable error displayed. Rebooting and retrying does not resolve the issue.\n\nInvestigation reveals two contributing factors. The affected user''s account is not a member of the required application-specific entitlement group in Azure AD, so the Intune deployment policy does not target the user or device and the application is not offered or installable. Concurrently, the device''s Intune inventory and policy state is stale — last-sync timestamps are often 24 hours or more old — meaning that even after entitlement group membership is corrected, updated policy is not reflected on the endpoint until a manual inventory and policy refresh is performed.\n\nIn some cases a prior support action had already added the user to the correct entitlement group, but the change did not propagate to the device due to the stale inventory state, causing the issue to persist or recur. The combination of missing entitlement assignment and outdated device policy sync prevents Software Center from presenting the application as available or allowing installation to proceed.", "cause": "The affected user was not a member of the required application entitlement group in Azure AD, so the deployment policy was not targeted to the endpoint. A stale Intune device inventory and policy state further obscured the issue by preventing updated group membership from being reflected on the device, causing Software Center policy evaluation to continue failing the entitlement check even after the initial access correction.", "variations": "- The application appears in Software Center but with the Install button disabled and an explicit entitlement policy failure code displayed upon retry.\n- The application is completely absent from both Software Center and Company Portal, with no error message surfaced to the user.\n- A direct local installer attempt outside Software Center also fails, returning \"installation blocked\" with an entitlement check error code.\n- The device shows a recent Company Portal sync timestamp, yet Intune inventory remains stale and does not reflect the user''s current group membership or role changes.\n- A previous entitlement remediation was applied but the issue returned because the device policy state was not refreshed to reflect the updated group membership.\n- The installation attempt returns a general download or install error code alongside the underlying entitlement policy check failure.", "reporting": "Resolved by IT after adding the affected user to the required entitlement group and refreshing stale device inventory and policy state so Software Center correctly reflected the updated deployment targeting."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:16:11.260637+00:00", "final_grade": "Accepted"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/missing-entitlement-plus-stale-inventory';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Endpoint Inventory and Policy State Blocking Application Deployment", "symptoms": "Affected users on Windows 10 21H2 managed endpoints experience application installation failures when attempting to deploy software through Software Center. The issue manifests as a policy check failure error (error code 0x87D13B5C) or an \"Installation blocked by policy\" message. In addition to the blocking error, the target application may disappear from the Available applications catalog in Software Center, preventing self-service installation entirely. Application assignments in Intune are confirmed to be correctly targeted to the affected user accounts and devices; the failure is attributable to the endpoint operating on stale inventory and policy data, causing it to fail to recognize valid deployments.\n\nThe issue has been observed to recur on the same device after earlier remediation. In one instance, a user''s initial incident involving one application was resolved, but the same device subsequently exhibited the identical stale-policy condition affecting a different application. The recurrence persisted until endpoint policy data was refreshed. In both occurrences, the affected user''s entitlement group membership and application targeting were verified as correct, confirming that the failure was due to outdated deployment metadata rather than any misconfiguration in assignment or identity. The failure is endpoint-specific; other devices under the same entitlement group are unaffected.", "cause": "Device inventory and policy state in Intune and Software Center were stale, so the endpoint did not have current application availability or policy evaluation data. This caused the entitlement evaluation for deployed applications to fail, meaning the applications were not shown correctly in Software Center and installation attempts were blocked by policy.", "variations": "- The blocked application may differ between occurrences on the same device (e.g., a CRM application in one instance and a sales demonstration tool in another), while the underlying stale-policy condition remains consistent.\n- Some affected users report that colleagues on other devices in the same office and entitlement group can see and install the application without issue, confirming the problem is endpoint-specific rather than tenant-wide.\n- The application may initially appear in a cached or stale Software Center listing but fail with a policy-block error on installation attempt, rather than being absent from the catalog from the outset.", "reporting": "Resolved by IT; referenced as stale endpoint inventory and policy state causing application deployment failure."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:18:10.867923+00:00", "final_grade": "Accepted"}' WHERE family = 'SIB' AND root_cause_id = 'SIB/stale-inventory-policy-targeting-only';
UPDATE wiki_pages SET curated_description = '{"title": "TOTP Clock Drift and Stale Factor Enrollment MFA Prompt Loop", "symptoms": "Affected users experience a repeated MFA challenge loop when attempting to sign in to SaaS applications (such as Office 365, Salesforce, Workday, and Concur) through the SSO portal. After entering their password and submitting a time-based one-time password (TOTP) from their authenticator app, the portal returns them to the MFA prompt rather than completing authentication. The authenticator app continues to generate codes that appear valid, but each submitted code is rejected, effectively blocking access to all federated applications behind the SSO portal.\n\nThe issue is traced to a mismatch between the time on the user''s authenticator device and the server''s expected TOTP window, caused by clock drift on the device. In some cases, stale MFA factor enrollments on the affected accounts compound the problem, preventing recovery even after device time is corrected. Identity provider logs show repeated MFA challenge failures against the affected accounts rather than any tenant-wide authentication error.\n\nThe issue has been observed on both mobile devices (iPhones running iOS 16) and desktop platforms (Windows 10), affecting users across multiple office locations. In some instances, the MFA loop appeared following an overnight maintenance window or a same-day mobile OS update, both of which preceded the onset of clock-related TOTP failures. The problem is isolated to individual user accounts and their enrolled devices rather than the identity provider tenant configuration or broader infrastructure.", "cause": "Clock drift on affected users'' authenticator devices caused TOTP codes to be generated out of sync with the identity provider''s expected validation window, resulting in repeated MFA challenge rejections and an SSO prompt loop. In several cases, stale MFA factor enrollment records — some not updated for over fourteen months — compounded the issue, preventing successful verification even after device time was corrected. Available evidence in some incidents did not fully isolate whether time drift alone or factor re-registration was the sole trigger.", "variations": "- A single user experienced the MFA loop on a personal iPhone with approximately eight minutes of clock drift, while colleagues in the same group were unaffected.\n- Multiple users in a sales group were simultaneously affected across both desktop and mobile authenticator apps, with the issue surfacing the morning after an overnight maintenance window.\n- A user''s device clock was corrected to automatic time sync, but the MFA loop persisted due to a stale factor enrollment on the account, requiring MFA reset and re-enrollment.\n- Stale MFA factor enrollments — some not updated for over fourteen months — were identified as a contributing factor alongside clock drift on affected accounts.\n- A same-day iOS update preceded the onset of the issue on a user''s mobile device, with the phone''s time appearing incorrect until manually set back to automatic.", "reporting": "Resolved by IT through device time synchronization correction and, where necessary, MFA factor reset and re-enrollment on the identity provider; reference as \"TOTP clock drift / stale factor enrollment MFA loop.\""}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:19:46.510588+00:00", "final_grade": "Accepted"}' WHERE family = 'SML' AND root_cause_id = 'SML/authenticator-clock-drift-totp-mismatch';
UPDATE wiki_pages SET curated_description = '{"title": "Stale MFA Enrollment and Group Policy Mismatch Cause SSO Authentication Loop", "symptoms": "Affected users across multiple departments—including Sales, Marketing, Engineering, Operations, and external contractor groups—were unable to complete sign-in to SaaS applications (such as Salesforce, Office 365, Concur, Confluence, Slack, Workday, and G Suite) through the corporate SSO portal federated with Okta and Azure AD. After entering valid credentials and approving the Okta Verify MFA prompt, users were immediately returned to another MFA challenge rather than being granted access. The loop persisted regardless of the application selected, the device used, or whether browser caches were cleared. In some cases, explicit error messages appeared, including \"Sign-in rejected,\" \"Authentication rejected,\" \"verification failed,\" or HTTP 401 MFA_REQUIRED responses.\n\nOkta system logs for affected accounts consistently showed repeated MFA challenge events with no successful verification callback, including token mismatch errors and SAML assertion rejections. Azure AD sign-in logs reflected corresponding conditional access denial events. In several instances, Azure AD showed successful token issuance for sessions that Okta simultaneously rejected, highlighting a desynchronization between the two identity platforms.\n\nThe issue consistently emerged following recent identity infrastructure changes—conditional access policy updates, Azure AD group attribute modifications, or scheduled identity sync operations. Investigation across all reported cases identified two co-occurring conditions: stale MFA factor enrollments on affected Okta accounts (sometimes tied to previously decommissioned devices or pre-migration factor schemas) and a group-based conditional access policy mismatch in Azure AD caused by incomplete group membership propagation or references to deprecated policy versions. Together, these conditions caused the authentication flow to loop indefinitely without completing the SSO handoff.", "cause": "Stale MFA enrollment records persisted on affected user accounts following identity sync operations or policy migrations between Azure AD and Okta. Concurrently, group-based conditional access policies referenced outdated group mappings, deprecated policy versions, or stale group object identifiers introduced during scheduled sync cycles or policy change windows. The combination of mismatched factor enrollment state and incorrect policy scope evaluation caused repeated MFA challenges without successful session completion.", "variations": "- Some affected users received an explicit \"Sign-in rejected\" or \"access_denied\" message rather than a silent MFA loop, with no corresponding approval activity visible in the authenticator app.\n- Azure AD logs for certain external contractor accounts showed token rejection errors specific to the contractor group conditional access rule set, confirming the issue was not limited to internal employees.\n- In one case, temporarily reassigning an affected user to a legacy access group immediately restored access, confirming the policy scope mismatch.\n- A legacy conditional access policy referencing deprecated enrollment mapping attributes from a pre-migration factor schema remained enabled, causing the loop specifically for users who re-enrolled after a factor migration.\n- Some affected users experienced intermittent access rather than a complete block, with the MFA loop occurring inconsistently across sign-in attempts.\n- One affected user confirmed that a colleague in the same Azure AD access group could sign in normally, indicating the issue was account-specific on a subset of group members.\n- A subset of users required individual MFA enrollment resets even after the policy-level fix was applied, due to factor enrollment metadata recorded under the old policy version.\n- An authenticator clock skew warning was observed on one affected device during the failure window, though the loop persisted independent of time synchronization.", "reporting": "Resolved by IT after resetting stale MFA factor enrollments and correcting the Azure AD group-based conditional access policy scope to restore SSO authentication."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:21:44.783157+00:00", "final_grade": "Accepted"}' WHERE family = 'SML' AND root_cause_id = 'SML/combined-stale-enrollment-and-policy-desync';
UPDATE wiki_pages SET curated_description = '{"title": "Group-Scope Policy Mismatch Between Okta and Azure AD Causes MFA Loop", "symptoms": "Affected users experience repeated MFA challenge loops when signing in to SaaS applications—including Salesforce, Office 365, Confluence, Workday, and Concur—through Okta SSO portals federated with Azure AD. After successfully completing MFA verification (via Okta Verify push or Microsoft Authenticator code), users are immediately redirected back to another MFA prompt rather than reaching the target application. In some cases, users receive explicit HTTP 401 or 403 access-denied errors instead of the repeated prompt. The issue affects cohorts of users within the same organizational group rather than isolated accounts, and is reproducible across different browsers, devices, and network locations.\n\nInvestigation reveals a mismatch between Okta group assignments and the group-based scoping of Azure AD conditional access policies. Okta system logs confirm successful MFA verification, yet Azure AD sign-in logs show conditional access denials—sometimes with error code 53003—or missing group claims in the issued token. The root cause traces to recent administrative changes such as group sync updates, organizational unit restructures, sign-on policy modifications, or conditional access rule changes that cause affected users to fall outside the intended policy scope in Azure AD.\n\nThe issue typically emerges shortly after an identity configuration change—such as a directory sync modification, group restructure, or conditional access policy update—and affects multiple users tied to specific group memberships such as contractor access, sales, or broad employee groups. MFA enrollment and factor state are confirmed healthy in the Okta admin console for affected users, confirming the failure is at the policy-evaluation layer rather than the MFA enrollment layer.", "cause": "Azure AD conditional access policy group scoping fell out of alignment with current Okta-sourced group assignments following administrative changes such as directory sync updates, organizational unit restructures, or policy modifications. Affected users were evaluated against incorrect or default conditional access policies during SSO, causing repeated MFA challenges or outright access denials despite valid MFA enrollment. In some incidents, a deprecated sign-on policy reference or an overly strict location-based conditional access rule contributed to the mismatch.", "variations": "- Some affected users received explicit HTTP 401/403 errors rather than experiencing the MFA prompt loop.\n- In one incident, authenticator device clock drift of approximately five to seven minutes on certain affected users'' mobile devices contributed additional sign-in failures alongside the policy mismatch.\n- Some users recovered after MFA factor re-enrollment in the Okta admin console, while others in the same cohort continued to experience the loop due to the underlying conditional access scope mismatch.\n- Azure AD sign-in logs in some cases showed missing group claims in the issued token rather than an explicit conditional access denial, preventing application access without a clear error message.\n- A subset of incidents involved a deprecated or legacy MFA policy reference in the Okta sign-on rule, causing login rejection even though users were correctly assigned to the appropriate application access group.\n- In one case, a location-based conditional access rule scoped to a specific regional group caused denials for on-site and VPN users alike at the affected office.\n- In one instance the issue was triggered by a manual organizational unit restructure, while in another it was triggered by a scheduled identity sync between Azure AD and Okta.\n- Certain users were affected on specific applications while others experienced the loop across a broader set of SaaS applications.", "reporting": "Resolved by IT after correcting Azure AD conditional access policy group scoping and Okta sign-on policy references to restore proper SSO evaluation for affected users."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:23:09.875918+00:00", "final_grade": "Accepted"}' WHERE family = 'SML' AND root_cause_id = 'SML/conditional-access-group-policy-mismatch';
UPDATE wiki_pages SET curated_description = '{"title": "Federated SSO Claim Mapping Fault Causes Post-MFA Session Loop", "symptoms": "Affected users were unable to access SaaS applications — including Salesforce, Office 365, and other targets — through the corporate SSO portal. The sign-in process appeared to loop back to the multi-factor authentication (MFA) prompt repeatedly: users would approve the Okta Verify push notification, see a brief loading screen, and then be returned to the MFA prompt rather than reaching the intended application. The issue began shortly after a scheduled identity platform change window that updated federation trust settings between Okta and Azure AD.\n\nDiagnostic investigation revealed that the behavior resembled an MFA loop but was not an MFA failure. Okta system logs showed a successful factor verification event followed by an immediate federation redirect failure, with the error indicating an invalid session state due to a missing group claim in the SAML assertion. MFA enrollment and conditional access policy assignments were confirmed healthy for all affected accounts. The root cause was traced to a misconfigured claim mapping in the Okta-to-Azure AD federation trust introduced during the change window, which omitted the contractor group claim from the SAML token.\n\nThe issue was observed among contractor accounts provisioned through a recently synced Azure AD contractor access group. Affected users reported the problem from the same office location and across multiple SaaS application targets, confirming the failure was not application-specific but tied to federated session handling for that contractor group.", "cause": "An upstream federated SSO processing fault occurred after MFA completion, preventing session establishment and redirecting users back to the sign-in flow. A misconfigured claim mapping in the Okta-to-Azure AD federation trust, introduced during a scheduled change window, omitted the contractor group claim from the SAML assertion, causing an invalid session state for affected contractor accounts.", "variations": "", "reporting": "Resolved by IT after correcting the federated claim mapping configuration that omitted the contractor group claim from the SAML assertion during the Okta-to-Azure AD trust update."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:24:23.707578+00:00", "final_grade": "Accepted"}' WHERE family = 'SML' AND root_cause_id = 'SML/post-mfa-federation-session-fault';
UPDATE wiki_pages SET curated_description = '{"title": "Stale Okta MFA Enrollment Records Cause SSO Challenge Loop", "symptoms": "Affected users attempting to sign in to the corporate Okta-backed SSO portal are unable to complete authentication. After entering primary credentials and approving the MFA challenge (via Okta Verify push or TOTP), the browser immediately returns to the MFA prompt rather than granting a session. This loop prevents access to downstream SaaS applications such as Salesforce, Workday, Confluence, Office 365, Google Workspace, and Slack. In some cases an explicit \"Authentication failed\" or AUTH-401 error appears between iterations; in others the prompt silently reappears with no error displayed. The behavior persists across multiple browsers, incognito sessions, alternate devices, and after client-side steps such as clearing cache or reinstalling the authenticator app.\n\nThe issue affects individual accounts and groups of up to approximately 14 users simultaneously, spanning multiple office locations, departments, and both internal employees and recently onboarded contractor accounts. Some affected users report that certain federated applications (e.g., ServiceNow) remain accessible while others are blocked, giving the appearance of an application-specific problem.\n\nOkta system logs for impacted accounts consistently show successful primary authentication followed by repeated factor challenge events, token validation failures (AUTH-401, ERR_MFA_ENROLL_STALE, invalid_token, access_denied, invalid_grant), factor-mismatch errors, and rejected SAML assertions. Investigation confirms that enrolled MFA factor identifiers no longer match the users'' current authenticator state, with access policy memberships and application assignments verified as correct in each case.", "cause": "Stale or mismatched MFA factor enrollment records within the Okta tenant caused device and credential bindings to fall out of sync with affected users'' current authenticator state. The condition has been observed following organizational MFA migrations (e.g., legacy TOTP to Okta Verify push), mobile device changes, authenticator app reinstallations, and directory synchronization events such as Azure AD Connect syncs or group migrations. In each scenario, the factor enrollment retained by Okta no longer matched the active authenticator instance, causing the identity provider to reject verification and re-issue the MFA challenge in a continuous loop.", "variations": "- In one incident, approximately 14 Sales group accounts were affected simultaneously following a scheduled MFA factor migration from legacy TOTP to Okta Verify push.\n- Some accounts contained duplicate TOTP factor enrollments (one stale, one current), with the stale entry triggering factor-mismatch events on each authentication attempt.\n- In one case, the affected user''s phone clock was not set to automatic; correcting this alone did not resolve the loop.\n- A mobile device OS update initially suggested an authenticator or clock-drift issue but was ultimately traced to stale factor enrollment.\n- Certain federated applications such as ServiceNow remained accessible while others were blocked, giving the appearance of an application-specific problem.\n- Contractor accounts exhibited intermittent behavior, with at least one user able to complete sign-in on one occasion but failing on subsequent attempts.\n- The issue affected users whose Okta Verify factor enrollment predated a recent Azure AD group migration, suggesting the migration contributed to enrollment staleness.\n- Prior self-service remediation attempts by users — including cache cleanup and re-adding the authenticator — did not resolve the loop, consistent with a server-side enrollment problem.", "reporting": "Affected users and their managers typically open tickets describing an inability to complete SSO login due to a repeating MFA prompt, often referencing a stale MFA enrollment prompt loop or endless MFA challenge after sign-in."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:28:10.319617+00:00", "final_grade": "Accepted"}' WHERE family = 'SML' AND root_cause_id = 'SML/stale-mfa-factor-enrollment';
UPDATE wiki_pages SET curated_description = '{"title": "Expired Device Certificate Causes Post-MFA GlobalProtect Tunnel Teardown", "symptoms": "Affected users on corporate-managed Windows 10, Windows 11, and macOS endpoints experience immediate GlobalProtect VPN disconnections after successfully completing Okta MFA authentication. The VPN client briefly displays a \"Connected\" status for approximately 2 to 40 seconds following a successful push approval, then the tunnel tears down automatically. Once disconnected, all internal resources — including intranet portals, HR and finance systems, CRM, Confluence, Jira, SharePoint, Salesforce, SMB file shares, email, and SSH bastion access — become completely unreachable. Repeated reconnection attempts reproduce the same cycle of successful MFA followed by momentary connectivity and rapid disconnection.\n\nGateway and client-side log analysis consistently reveals that the tunnel teardown is triggered by a TLS handshake or device certificate validation failure occurring during the post-authentication phase. The affected endpoints present expired device certificates issued by the organization''s internal Device Certificate Service. The gateway rejects the session with a certificate-expired error despite valid user-level MFA credentials. In several cases, the certificate expirations aligned with scheduled rotation windows that failed to complete renewals on all endpoints, or followed Windows cumulative updates that prevented automatic certificate renewal.\n\nThe issue has been observed across multiple offices, geographic regions, and VPN gateways, affecting individual users as well as groups of users whose certificates expired around the same date. It is not related to network connection type and reproduces on both wired and wireless connections. In some cases, stale GlobalProtect VPN profiles cached on affected endpoints — referencing outdated certificate thumbprints — compound the failure or cause recurrence after initial remediation. Standard user-side troubleshooting such as client restarts, device reboots, and local profile refreshes does not resolve the problem while the expired certificate remains in the endpoint''s certificate store.", "cause": "Expired device certificates on affected managed endpoints caused GlobalProtect post-authentication certificate validation to fail immediately after successful Okta MFA approval, triggering VPN tunnel teardown. In some cases, stale GlobalProtect VPN profiles that referenced outdated certificate thumbprints compounded the issue or caused recurrence after initial certificate renewal.", "variations": "- Tunnel uptime before disconnection varied from as little as 2 seconds to as long as 40 seconds after reaching \"Connected\" status, depending on when post-MFA certificate validation occurred.\n- Some affected endpoints also carried stale GlobalProtect VPN profiles referencing outdated certificate thumbprints, requiring both certificate renewal and profile refresh to fully resolve.\n- In some cases the GlobalProtect client entered a persistent reauthentication loop after disconnection rather than simply dropping the session.\n- The issue was observed on macOS 12 endpoints in addition to Windows 10 and Windows 11 managed laptops, requiring platform-specific re-enrollment workflows.\n- In at least one case the device certificate was not expired but had been improperly re-enrolled during a previous rotation cycle, producing the same validation failure.\n- Some users reported seeing device certificate expiration warnings in the system tray days before the VPN connectivity issue manifested.\n- In certain instances, Windows cumulative security updates prevented automatic certificate renewal, leaving the endpoint certificate in an expired state.\n- The issue affected both individual endpoints and clusters of users within the same team or certificate rotation batch simultaneously.", "reporting": "Resolved by IT through device certificate renewal via the Device Certificate Service and, where applicable, a GlobalProtect VPN profile refresh on the affected endpoint."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:34:45.222961+00:00", "final_grade": "Accepted"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/expired-device-certificate-post-mfa-validation-failure';
UPDATE wiki_pages SET curated_description = '{"title": "Post-Authentication GlobalProtect Gateway Instability Terminating VPN Sessions", "symptoms": "Multiple remote users on managed Windows 10 laptops experienced repeated disconnections when connecting to the corporate network through GlobalProtect VPN. After successfully approving the MFA push notification, the VPN client briefly reached a \"Connected\" state but then dropped the connection within three to five seconds. The rapid disconnection prevented access to internal resources including the corporate intranet, Confluence, and Salesforce. The issue persisted across repeated sign-in attempts throughout the morning.\n\nThe problem was not isolated to a single user or region. At least five remote workers across multiple geographic locations reported identical behavior, ruling out endpoint-specific causes. Diagnostics confirmed that MFA authentication completed successfully for all affected users and that no endpoint certificate issues were present on any of the tested devices.\n\nInvestigation revealed that the underlying failure occurred during post-authentication session establishment on the VPN gateway. Multiple clients recorded gateway resets, with IKE negotiation being aborted after authentication had already succeeded, along with portal timeout behavior during the post-auth phase. The consistent pattern across all affected regions pointed to a VPN service-side issue on the gateway rather than any endpoint or user-level problem.", "cause": "Post-authentication instability on the GlobalProtect gateway or portal was terminating VPN sessions after successful MFA validation. The gateway was resetting connections during the session establishment phase, causing widespread disconnects despite valid endpoint certificate configurations across affected devices.", "variations": "", "reporting": "The issue was resolved by IT after identifying and correcting post-authentication gateway instability that was terminating GlobalProtect VPN sessions following successful MFA validation."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:35:57.791245+00:00", "final_grade": "Accepted"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/gateway-portal-post-auth-instability';
UPDATE wiki_pages SET curated_description = '{"title": "GlobalProtect Profile Certificate Mapping Mismatch Causing Post-Auth Disconnects", "symptoms": "Affected users on managed Windows 10 laptops experienced repeated VPN disconnections when connecting to the corporate network via GlobalProtect while working remotely. After successfully approving the MFA prompt, the VPN session appeared to establish briefly — typically for approximately 10 to 20 seconds — before dropping automatically. During the short-lived connection, internal applications such as the corporate intranet and Confluence sometimes began loading partially but became unreachable once the tunnel terminated. The issue was reproducible across multiple reconnect attempts and affected multiple users in the same department whose devices had recently received a VPN profile update.\n\nDiagnostics confirmed that MFA authentication was completing successfully for all affected users and that the device certificates installed on the endpoints remained valid. However, the GlobalProtect profile pushed to affected devices referenced an incorrect enrolled certificate. Specifically, the profile pointed to an old certificate thumbprint that no longer matched the currently enrolled certificate from the Device Certificate Service. This mismatch caused post-authentication policy evaluation to fail, producing a VPN-ERR-201 error in diagnostic logs, which in turn caused the client to terminate the tunnel immediately after login.", "cause": "A GlobalProtect profile misconfiguration on affected endpoints caused the client to use a certificate mapping that did not match the active enrolled device certificate. This triggered post-authentication policy disconnects after successful MFA validation.", "variations": "", "reporting": "The issue was resolved by IT after correcting the GlobalProtect profile to reference the current enrolled device certificate thumbprint."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:36:49.811670+00:00", "final_grade": "Accepted"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/globalprotect-profile-cert-mapping-misconfiguration';
UPDATE wiki_pages SET curated_description = '{"title": "Intermittent GlobalProtect VPN Disconnections After Successful MFA Authentication", "symptoms": "An affected remote user experienced intermittent VPN disconnections while connecting to the corporate network via GlobalProtect from a managed Windows laptop. The VPN session dropped around the time of the Okta MFA prompt, rendering internal sites such as the intranet application and line-of-business applications unreachable. The disconnections could not be reproduced consistently during the support session.\n\nThe affected user confirmed that the Okta push notification was successfully approved each time, with authentication completing as expected. The GlobalProtect client briefly indicated a successful connection — the system tray icon turned green — before disconnecting within approximately five to ten seconds. Internal applications never became accessible during these brief sessions. The same behavior was observed from two different external networks.\n\nDiagnostic review ruled out an expired or mismatched device certificate on the affected endpoint. However, the remaining collected logs did not isolate whether the disconnect originated from transient client behavior, a network interruption, or a gateway-side event. The root cause could not be confirmed to a single failure point from the available evidence.", "cause": "Insufficient evidence was available to determine a definitive root cause. Certificate-related causes were ruled out during diagnostic review, and the remaining disconnect behavior appeared intermittent with no single failure point identified.", "variations": "", "reporting": "Resolved by IT; reference intermittent GlobalProtect VPN disconnections following successful Okta MFA authentication with no confirmed root cause."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:37:41.264655+00:00", "final_grade": "Accepted"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/indeterminate-intermittent-disconnect';
UPDATE wiki_pages SET curated_description = '{"title": "Stale VPN Profile After Certificate Renewal Causes Tunnel Teardown", "symptoms": "Affected users on managed Windows 10 laptops experience repeated GlobalProtect VPN disconnections shortly after successful Okta MFA authentication. The VPN client briefly displays a \"Connected\" status for approximately three to ten seconds before dropping back to \"Disconnected.\" During the brief connection window, internal resources such as the corporate intranet, SMB file shares, and internal-only email remain unreachable. The disconnection behavior is consistent and reproducible across multiple connection attempts from the same endpoint.\n\nThe issue arises after a device certificate renewal has been performed or pushed to the endpoint. Although the renewed certificate is present, the endpoint retains an outdated local VPN profile that references the previous certificate association. This mismatch causes the VPN gateway to tear down the tunnel immediately after authentication succeeds. Gateway and client log review confirms that MFA authentication and tunnel establishment complete successfully before the termination occurs, ruling out credential or MFA issues.\n\nThe problem is isolated to specific endpoints rather than being a network-wide or account-wide condition. In observed cases, a colleague on the same team connecting from the same office location did not experience the issue, indicating that the root cause is tied to the individual device''s local profile state.", "cause": "The GlobalProtect client retained a stale local VPN profile after a device certificate renewal, creating a mismatch between the renewed certificate and the active profile''s certificate association. After successful MFA authentication, the gateway session failed device certificate validation and posture checks, tearing down the tunnel during reauthentication.", "variations": "- In one case, the affected user reported that internal-only email access was also unreachable during the brief connection window, in addition to intranet and file share resources.\n- One affected endpoint retained a stale VPN profile dated approximately two months prior to the most recent certificate push, confirming a significant gap between the profile timestamp and the renewed certificate.\n- Not all devices on the same team or office network were affected; a colleague of one affected user on the same team did not experience the disconnection, underscoring the endpoint-specific nature of the issue.", "reporting": "Resolved by IT; stale GlobalProtect VPN profile and certificate association mismatch causing post-MFA tunnel teardown."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:38:49.518631+00:00", "final_grade": "Accepted"}' WHERE family = 'VDA' AND root_cause_id = 'VDA/stale-vpn-profile-blocking-renewed-certificate';
UPDATE wiki_pages SET curated_description = '{"title": "Incomplete EAP-TLS Certificate Propagation Across Wireless Controller Cluster", "symptoms": "Affected users across multiple offices report that managed Windows, macOS, and Android devices fail to authenticate or maintain connectivity on the corporate Wi-Fi SSID following a scheduled wireless certificate rollover. Devices attempting 802.1X/EAP-TLS authentication receive errors such as \"EAP-TLS certificate expired,\" \"certificate verification failed,\" or \"Access denied by NAC,\" and are either unable to join the network or briefly associate before losing all network access. The issue affects users across multiple floors, teams, and device platforms simultaneously.\n\nInvestigation consistently reveals that the wireless controller''s RADIUS server certificate has either expired or was not fully propagated to all nodes in the controller cluster after renewal. In some cases the renewed certificate is present on the primary controller but absent from secondary cluster members, causing authentication failures to persist even after an initial partial restoration of service. NAC and RADIUS logs confirm EAP-TLS trust chain errors as the root cause of client denials, with affected devices referencing stale or expired certificate data during the authentication handshake.\n\nAfter the correct certificate is deployed across all controller nodes and authentication services are restarted, most devices reconnect successfully. However, a subset of endpoints — particularly older clients or those with cached wireless profiles — continue to fail until the locally stored Wi-Fi profile is manually removed and the device is re-enrolled or rejoined to the corporate SSID. Temporary NAC exceptions may briefly restore access but do not resolve the underlying authentication failure.", "cause": "The renewed EAP-TLS server certificate and trust chain were not fully propagated across all wireless controller cluster nodes and the NAC/RADIUS authentication infrastructure after a scheduled certificate rotation. As a result, some authentication paths continued to present or validate against expired certificate data, causing 802.1X failures. A subset of managed endpoints also retained stale or corrupt corporate Wi-Fi profiles, perpetuating certificate validation errors even after the primary controller was updated.", "variations": "- Some devices associate to the SSID and briefly obtain a DHCP lease before access is revoked, while others fail authentication immediately and never receive an IP address.\n- A subset of Windows laptops require full wireless profile re-enrollment even after the server-side certificate is corrected, due to cached stale certificate references in the local supplicant configuration.\n- In multi-node controller clusters, service may be restored for users authenticating through the primary controller while users roaming to or served by secondary nodes continue to experience failures.\n- Temporary NAC policy exceptions provide short-lived connectivity but fail to persist across reconnection attempts the following day.\n- Android and older client devices are disproportionately likely to require a manual forget-and-rejoin cycle compared to newer Windows or macOS endpoints.", "reporting": "Resolved by IT after fully propagating the renewed EAP-TLS certificate across all wireless controller cluster nodes, restarting authentication services, and re-enrolling affected endpoint Wi-Fi profiles."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:39:31.503204+00:00", "final_grade": "Accepted"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/cert-rollover-incomplete-trust-propagation';
UPDATE wiki_pages SET curated_description = '{"title": "Expired Wireless Controller or RADIUS Certificate Blocks 802.1X Authentication", "symptoms": "Affected users across multiple office locations report that managed and personal devices (Windows, macOS, iOS, and Android) fail to authenticate to corporate Wi-Fi SSIDs. Devices detect and associate with the network but fail during the 802.1X EAP-TLS handshake, producing errors such as \"authentication failed,\" \"certificate expired,\" or \"secure connection failed.\" Users are left without corporate network access, and the issue impacts large groups simultaneously — spanning multiple floors, departments, and geographic sites served by the same wireless controller or RADIUS infrastructure.\n\nThe failure consistently originates from an expired server-side TLS certificate presented during EAP authentication. Some devices fail outright and disconnect immediately, while others briefly associate and display a \"Connected, no internet\" or \"No Internet, secured\" status before losing access. In certain cases, devices obtain only a link-local address rather than a valid DHCP lease. Wireless controller, RADIUS, and NAC logs show repeated Access-Reject events with certificate-expired reason codes accumulating after the expiration timestamp. Wired connectivity and guest wireless SSIDs remain fully functional, confirming the issue is isolated to the secured corporate wireless authentication path.\n\nStandard client-side troubleshooting — including rebooting devices, forgetting and rejoining the SSID, or re-entering credentials — does not restore connectivity while the expired certificate remains in place. The onset of failures frequently coincides with a scheduled certificate rotation window during which the renewed certificate was not properly applied or the prior certificate was allowed to lapse.", "cause": "The TLS server certificate used by the wireless controller or RADIUS infrastructure for 802.1X EAP-TLS authentication expired, causing all client certificate validation attempts to fail. The RADIUS service continued presenting the expired certificate during EAP handshakes, resulting in Access-Reject responses and NAC denial for every authenticating endpoint. In some incidents, the expiration occurred during or immediately before a scheduled certificate rotation window, indicating the renewed certificate was not applied before the prior certificate lapsed.", "variations": "- Some devices displayed explicit certificate trust warnings or 802.1X certificate problem alerts (particularly on mobile devices), while others showed only generic authentication failure messages or disconnected silently\n- In at least one instance, the expired certificate was an intermediate certificate in the authentication chain rather than the primary server certificate\n- The issue affected EAP-PEAP authentication in addition to EAP-TLS at some sites, as the expired server certificate impacted both methods\n- BYOD devices (personal smartphones and tablets) were affected alongside managed laptops, with both device types failing identically\n- In multi-node RADIUS cluster deployments, all cluster members presented the same expired certificate, causing site-wide authentication rejection rather than a partial outage\n- At certain sites the certificate expired minutes before a scheduled certificate refresh window opened, creating a narrow gap during which no valid certificate was in place\n- Affected devices sometimes obtained an APIPA (link-local) address instead of a valid DHCP lease, indicating authentication was rejected before network access was granted\n- A subset of endpoints required Wi-Fi profile removal and certificate re-enrollment (sometimes via MDM) after the infrastructure certificate was renewed, due to retained stale trust or profile state on the endpoint", "reporting": "The issue was resolved after the expired wireless controller and RADIUS server certificate was renewed and applied to the authentication infrastructure, with affected endpoint profiles remediated where necessary."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:47:24.494238+00:00", "final_grade": "Accepted"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/expired-radius-controller-eap-tls-certificate';
UPDATE wiki_pages SET curated_description = '{"title": "Incorrect NAC Policy Mapping Causes Post-Authentication VLAN Misassignment", "symptoms": "Affected users on managed corporate devices—including Windows laptops, iOS, and Android mobile devices—are able to associate with the corporate Wi-Fi SSID and successfully complete 802.1X (EAP-TLS or WPA2-Enterprise) authentication. However, immediately or shortly after authentication, devices either lose network access entirely, are placed into a quarantine or guest VLAN, or experience repeated disconnects. Users typically observe a brief period of apparent connectivity followed by \"No network access\" or \"Limited connectivity\" indicators, EAP timeout messages, and 802.1X authentication failure events in system logs. Reconnection attempts cycle between \"authenticating\" and \"disconnected\" states without restoring normal corporate access.\n\nThe issue consistently traces to a recent NAC policy change or scheduled configuration push. Following the update, the authorization profile mapping for one or more device groups is incorrect—valid, authenticated corporate endpoints are matched against the wrong policy rule, resulting in assignment to a quarantine role, guest VLAN, or deny profile instead of the intended corporate access profile. NAC and RADIUS session logs confirm successful authentication but show an erroneous enforcement profile being applied. The misconfiguration typically involves an altered Active Directory group-to-policy mapping or an incorrectly remapped organizational unit path.\n\nThe impact spans multiple users and device types within a given site or device group, often affecting entire floors or functional teams. In some cases the affected device obtains guest-range network connectivity that lacks access to internal resources while appearing connected. Stale VLAN bindings on the wireless controller may allow the misassignment to persist intermittently even after temporary remediation. Once the correct group-to-policy assignment is restored and stale session bindings are cleared, affected users regain full corporate network access.", "cause": "An incorrect Active Directory group-to-NAC policy mapping, introduced during a scheduled configuration push, caused successfully authenticated corporate endpoints to be evaluated against a quarantine, guest, or deny policy instead of the intended corporate access policy. Stale VLAN bindings on the wireless controller allowed the misassignment to persist intermittently for some devices after initial remediation attempts.", "variations": "- Some affected devices are placed into a guest VLAN (receiving a guest-range IP address) rather than a quarantine VLAN, resulting in Wi-Fi connectivity but no access to internal resources such as file shares, intranet portals, or CRM systems.\n- In certain cases, 802.1X authentication itself fails outright with RADIUS reject responses, preventing devices from completing the join process rather than connecting with restricted access.\n- The issue may present as intermittent disconnects with repeated EAP timeout errors rather than a persistent quarantine or guest VLAN assignment.\n- Both managed laptops and enrolled mobile devices (iOS and Android) are affected at the same site, confirming the issue is policy-based rather than platform- or certificate-specific.\n- Removing and rejoining the wireless profile, renewing device certificates, or rebooting does not resolve the VLAN misassignment, as the fault lies in the NAC policy configuration rather than the endpoint state.\n- Contractors authenticated via the same corporate SSID are affected alongside regular staff when their accounts fall under the misconfigured group mapping.", "reporting": "Resolved by IT after correcting the NAC policy group-to-VLAN mapping and clearing stale session bindings on the wireless controller."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:49:18.261464+00:00", "final_grade": "Accepted"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/incorrect-nac-policy-assignment';
UPDATE wiki_pages SET curated_description = '{"title": "Corrupted Endpoint Wireless Profile Causes Intermittent 802.1X Authentication Failure", "symptoms": "Affected users on Windows 10 laptops report that their devices successfully associate with the corporate Wi-Fi SSID but lose network access shortly after joining — typically within one minute. The wireless adapter displays a status of \"Connected, no network access\" or \"No Internet,\" and internal resources such as wikis, repositories, file shares, and email become unreachable. Rebooting or forgetting and rejoining the SSID may temporarily restore connectivity, but the failure recurs within minutes to roughly 30 minutes. The issue is device-specific; personal devices and other corporate endpoints on the same floor and access points connect without difficulty.\n\nInvestigation consistently reveals a stale or corrupted client-side wireless profile on the affected endpoint. The local 802.1X supplicant references outdated certificate thumbprints or retains cached authentication state that causes EAP-TLS negotiation to fail after initial association. Wireless controller and RADIUS/NAC logs confirm dropped 802.1X sessions — typically with a \"Session-Timeout\" reason or an outright Access-Reject — along with stale entries in the NAC session table for the affected device. Prior remediation attempts such as certificate renewals provide only temporary relief when the underlying profile corruption is not fully addressed.\n\nThe issue has been observed on individual endpoints as well as in small clusters of managed laptops (up to approximately six devices) on the same office floor, particularly following scheduled wireless profile updates or certificate renewal events. In multi-device occurrences, the root cause traces to endpoint configuration drift where devices lack the current managed Wi-Fi profile and consequently fail NAC evaluation, rather than a broader infrastructure outage.", "cause": "A corrupted or stale corporate wireless profile on the endpoint retained outdated certificate thumbprints and cached supplicant state, causing inconsistent 802.1X EAP-TLS authentication. This prevented full NAC authorization and resulted in repeated session drops or access rejections by the RADIUS infrastructure. In multi-device cases, scheduled profile updates introduced configuration drift across a subset of managed laptops.", "variations": "- Some affected devices experience intermittent disconnects specifically when roaming near certain access points, with transient controller-side instability observed during the recovery window but normalizing after endpoint remediation.\n- In a subset of cases, the issue resurfaces the day after a prior certificate renewal that had only temporarily restored service, indicating the renewed certificate alone did not resolve the underlying stale profile state.\n- A small cluster of managed laptops on the same office floor may be affected simultaneously following a scheduled wireless profile update, presenting as endpoint configuration drift rather than an isolated single-device problem.\n- Some devices receive an outright RADIUS Access-Reject during EAP-TLS authentication rather than connecting briefly before losing access.", "reporting": "Resolved by IT through removal and re-provisioning of the corrupted corporate wireless profile and clearance of stale NAC session state on the affected endpoints."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:50:12.840646+00:00", "final_grade": "Accepted"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/stale-or-corrupt-client-wifi-profile';
UPDATE wiki_pages SET curated_description = '{"title": "Intermittent 802.1X Wi-Fi Rejection After Certificate Rotation and Profile Mismatch", "symptoms": "Affected users on managed Windows laptops reported intermittent failures connecting to or remaining on the corporate Wi-Fi SSID using 802.1X authentication. Devices could typically join the SSID but were then rejected by the Network Access Control system or failed to obtain an IP address, resulting in a loss of network connectivity. In some cases, connection prompts failed immediately with an authentication error, while in others devices connected briefly before dropping. The issue often required multiple reconnection attempts and was not consistently resolved by retrying alone.\n\nAcross both incidents, the scope was limited — one affected roughly seven users in a Sales group following a wireless controller certificate rotation, and the other affected approximately four to five users on a single office floor. Diagnostic evidence was mixed: some endpoints exhibited expired EAP certificates or outdated Wi-Fi profile revisions, while others with current profiles and certificates still experienced post-association drops. RADIUS and NAC logs showed sporadic 802.1X timeouts and endpoint rejections for some users but clean sessions for others on the same network, making it difficult to isolate a single failing layer.", "cause": "Wireless controller certificate rotation restored only part of the 802.1X trust chain. Several endpoints still carried stale corporate Wi-Fi profiles or certificate bindings, and NAC policy evaluation continued rejecting some Sales devices until profiles were re-enrolled and policy alignment was corrected. Insufficient evidence existed to confirm whether the primary cause was endpoint Wi-Fi profile inconsistency, intermittent NAC rejection, or short-lived wireless infrastructure instability.", "variations": "- Some devices received an immediate \"Authentication Failed\" message upon joining the SSID, rather than connecting and then losing access\n- In one incident, a wireless controller certificate rotation preceded the onset of failures; renewing the controller certificate restored service for a subset of devices but not all\n- Certain endpoints required both certificate renewal and Wi-Fi profile re-push via MDM to restore connectivity\n- RADIUS logs showed sporadic 802.1X timeouts for specific users while sessions for other users on the same SSID completed cleanly\n- One endpoint had an outdated Wi-Fi profile revision while a neighboring device with the current profile still experienced drops", "reporting": "Resolved by IT through a combination of wireless controller certificate renewal, endpoint Wi-Fi profile re-enrollment via MDM, and NAC policy realignment."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:52:04.355243+00:00", "final_grade": "Accepted"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/unclassified-insufficient-evidence';
UPDATE wiki_pages SET curated_description = '{"title": "Wireless AP Radio Instability Causing Repeated Client Deauthentication", "symptoms": "Affected users on a single floor of an office building reported that their managed Windows 10 laptops could successfully join the corporate 5 GHz Wi-Fi SSID but were repeatedly dropped within two to five minutes of connecting. The disconnections interrupted access to internal applications and the corporate intranet. Users could sometimes reconnect briefly, but the cycle of association followed by disconnection recurred persistently. The issue was concentrated to one floor and did not affect wireless users on other floors or at other sites.\n\nInitial investigation considered certificate renewal and 802.1X authentication problems, but diagnostic analysis confirmed that clients were authenticating correctly against RADIUS. Controller-side logs revealed unstable behavior on two specific access points serving the affected floor. These APs were issuing repeated deauthentication events with reason code 6 (Class 2 frame received from nonauthenticated station) shortly after client association. Affected devices were observed bouncing between the two unstable APs every one to three minutes, preventing any sustained network session.\n\nThe issue presented as a localized connectivity disruption tied to radio and controller instability rather than a broader authentication or network access control failure. Multiple members of the same team on the affected floor reported identical symptoms during a narrow time window, while colleagues on adjacent floors remained unaffected.", "cause": "Wireless access point or controller radio instability in the affected area caused repeated client deauthentication and session drops after otherwise successful Wi-Fi authentication.", "variations": "- Some affected laptops appeared connected to the SSID but had no network access or no IP address assigned, rather than being fully disconnected.\n- A subset of users required multiple manual reconnection attempts before achieving even brief connectivity.", "reporting": "Resolved by IT after identifying and addressing access point radio instability on the affected floor; reference wireless AP deauthentication and session drop issue."}', curation_details = '{"model": "claude-opus-4-6", "pipeline_version": "experiment-aggregator-v1", "curated_at": "2026-06-27T15:52:35.383079+00:00", "final_grade": "Accepted"}' WHERE family = 'WCI' AND root_cause_id = 'WCI/wireless-rf-controller-instability';
COMMIT;
